{
  "name": "EbbFlow",
  "description": "A minimalist vocabulary retention app using the Ebbinghaus forgetting curve algorithm.",
  "requestFramePermissions": []
}

export interface Word {
  id: string;
  original: string;
  translation: string;
  phonetic?: string;
  exampleSentence: string;
  stage: number; // 0-8
  createdAt: number;
  nextReviewDate: number;
  lastReviewDate: number;
}

export const REVIEW_INTERVALS = [
  0,                  // Stage 0: Immediate
  5 * 60 * 1000,      // Stage 1: 5 mins
  30 * 60 * 1000,     // Stage 2: 30 mins
  12 * 60 * 60 * 1000,// Stage 3: 12 hours
  24 * 60 * 60 * 1000,// Stage 4: 1 day
  2 * 24 * 60 * 60 * 1000, // Stage 5: 2 days
  4 * 24 * 60 * 60 * 1000, // Stage 6: 4 days
  7 * 24 * 60 * 60 * 1000, // Stage 7: 7 days
  15 * 24 * 60 * 60 * 1000 // Stage 8: 15 days
];

export enum View {
  HOME = 'home',
  REVIEW = 'review',
  LIST = 'list',
  STATS = 'stats'
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface TranslationResult {
  translation: string;
  phonetic: string;
  exampleSentence: string;
}

export const getTranslation = async (text: string): Promise<TranslationResult> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Translate the following text. If it is English, translate to Chinese. If it is Chinese, translate to English. Provide the translation, a IPA phonetic transcription (if applicable), and one natural example sentence using the word in its original language. Text: "${text}"`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          translation: { type: Type.STRING },
          phonetic: { type: Type.STRING },
          exampleSentence: { type: Type.STRING },
        },
        required: ["translation", "phonetic", "exampleSentence"]
      }
    }
  });

  return JSON.parse(response.text);
};

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useCallback } from 'react';
import { Search, Brain, List, BarChart3, Plus, ChevronRight, Volume2, Trash2, Check, X, Undo2 } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);

  // Load data
  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      setWords(JSON.parse(saved));
    }
  }, []);

  // Save data
  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
