    if (!translationResult) return;
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 0,
      createdAt: Date.now(),
      lastReviewDate: Date.now(),
      nextReviewDate: Date.now() + REVIEW_INTERVALS[0]
    };
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, 8) : 0;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: Date.now(),
          nextReviewDate: Date.now() + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const dueWords = words.filter(w => Date.now() >= w.nextReviewDate);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm">
      {/* Header */}
      <header className="px-6 pt-8 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-2xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-8 rounded-full"></span>
          EbbFlow
        </h1>
      </header>

      {/* Main Content */}
      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="Enter text to translate..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-2 focus:ring-blue-500/20 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button 
                  type="submit"
                  disabled={loading}
                  className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 hover:bg-blue-50 transition-colors"
                >
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-2xl p-6 shadow-sm border border-slate-100 space-y-4 animate-in slide-in-from-top-4 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1">
                      <h3 className="text-xl font-medium text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-2 text-slate-400 hover:text-blue-500 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>
                  <p className="text-slate-600 italic leading-relaxed text-sm">
                    "{translationResult.exampleSentence}"
                  </p>
                  <button 
                    onClick={addToMemory}
                    className="w-full py-4 rounded-xl bg-blue-500 text-white font-medium hover:bg-blue-600 transition-colors flex items-center justify-center gap-2"
                  >
                    <Brain size={18} />
                    Add to Memory
                  </button>
                </div>
              )}
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between">
                 <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400">Current Status</h2>
                 <span className="text-xs text-blue-500 font-medium px-2 py-1 bg-blue-50 rounded-lg">
                    {dueWords.length} cards due
                 </span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm">
                    <p className="text-xs text-slate-400 mb-1">Total Words</p>
                    <p className="text-2xl font-semibold text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-2xl border border-slate-100 shadow-sm">
