                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400 mb-6">Vocabulary List</h2>
