                <div key={w.id} className="bg-white p-4 rounded-xl border border-slate-100 flex items-center justify-between group">
                  <div>
                    <h4 className="font-medium text-slate-800">{w.original}</h4>
                    <p className="text-sm text-slate-400">{w.translation} • Stage {w.stage}</p>
                  </div>
                  <button onClick={() => deleteWord(w.id)} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                    <Trash2 size={18} />
                  </button>
                </div>
              ))
            )}
          </div>
        )}

        {activeView === View.STATS && (
           <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-sm font-semibold uppercase tracking-wider text-slate-400">Memory Heatmap</h2>
              <div className="bg-white p-6 rounded-2xl border border-slate-100 shadow-sm">
                <div className="flex flex-wrap gap-2">
                  {Array.from({ length: 140 }).map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-3 h-3 rounded-sm ${i % 7 === 0 ? 'bg-blue-400' : 'bg-slate-100'}`} 
                      title="Placeholder Stat"
                    />
                  ))}
                </div>
                <p className="text-xs text-slate-400 mt-4 text-center italic">Future update: Real historical activity tracking</p>
              </div>
           </div>
        )}
      </main>

      {/* Navigation */}
      <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 bg-white/80 backdrop-blur-xl border border-white/50 shadow-2xl rounded-3xl p-2 flex items-center gap-1">
        <NavButton active={activeView === View.HOME} onClick={() => setActiveView(View.HOME)} icon={<Search size={20} />} label="Explore" />
        <NavButton 
          active={activeView === View.REVIEW} 
          onClick={() => setActiveView(View.REVIEW)} 
          icon={<Brain size={20} />} 
          label="Review" 
          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={20} />} label="List" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={20} />} label="Stats" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; badge?: number }> = ({ active, onClick, icon, label, badge }) => (
  <button 
    onClick={onClick}
    className={`relative px-5 py-3 rounded-2xl flex flex-col items-center gap-1 transition-all ${active ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/30 scale-105' : 'text-slate-400 hover:bg-slate-100'}`}
  >
    {icon}
    <span className="text-[10px] font-medium tracking-wide">{label}</span>
    {badge !== undefined && !active && (
      <span className="absolute top-2 right-4 w-4 h-4 bg-red-500 text-white text-[10px] flex items-center justify-center rounded-full animate-bounce">
        {badge}
      </span>
    )}
  </button>
);

const ReviewMode: React.FC<{ words: Word[]; onReview: (id: string, rem: boolean) => void; onSpeak: (t: string) => void }> = ({ words, onReview, onSpeak }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);

  const currentWord = words[currentIndex];

  if (!currentWord) {
    return (
      <div className="flex flex-col items-center justify-center py-20 space-y-6 text-center animate-in zoom-in duration-500">
        <div className="w-20 h-20 bg-green-50 rounded-full flex items-center justify-center text-green-500">
          <Check size={40} />
        </div>
        <div className="space-y-2">
          <h2 className="text-2xl font-light text-slate-800">Peace of Mind</h2>
          <p className="text-slate-400">All caught up! Check back later or add new words.</p>
        </div>
      </div>
    );
  }

  const handleAction = (remembered: boolean) => {
    onReview(currentWord.id, remembered);
    setFlipped(false);
    // Move to next word (actual state change will remove from array anyway)
    // No need to manually increment if we're filtering due words
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-center px-2">
        <span className="text-xs font-semibold text-slate-400 uppercase tracking-widest">Stage {currentWord.stage}</span>
        <span className="text-xs text-slate-400">{currentIndex + 1} of {words.length}</span>
      </div>

      <div 
        onClick={() => setFlipped(!flipped)}
        className="relative h-80 w-full perspective-1000 cursor-pointer group"
      >
        <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${flipped ? 'rotate-y-180' : ''}`}>
          {/* Front */}
          <div className="absolute inset-0 bg-white rounded-[2rem] border border-slate-100 shadow-xl shadow-slate-200/50 flex flex-col items-center justify-center p-12 backface-hidden">
            <h3 className="text-4xl font-light text-slate-800 text-center leading-tight">{currentWord.original}</h3>
            <p className="mt-8 text-slate-300 text-sm flex items-center gap-2">
              Tap to reveal <ChevronRight size={14} />
            </p>
          </div>

          {/* Back */}
          <div className="absolute inset-0 bg-white rounded-[2rem] border border-slate-100 shadow-xl shadow-slate-200/50 flex flex-col items-center justify-center p-10 backface-hidden rotate-y-180 text-center space-y-4">
            <div className="space-y-1">
              <h3 className="text-3xl font-medium text-slate-800">{currentWord.translation}</h3>
              <p className="text-slate-400 font-mono text-sm">{currentWord.phonetic}</p>
            </div>
            <div className="h-[1px] w-12 bg-slate-100 my-2"></div>
            <p className="text-slate-600 italic text-sm leading-relaxed px-4">
              "{currentWord.exampleSentence}"
            </p>
            <button 
              onClick={(e) => { e.stopPropagation(); onSpeak(currentWord.original); }} 
              className="p-3 bg-slate-50 rounded-full text-slate-400 hover:text-blue-500 transition-colors"
            >
              <Volume2 size={24} />
            </button>
          </div>
        </div>
      </div>

      {flipped && (
        <div className="flex gap-4 animate-in slide-in-from-bottom-4 duration-300">
          <button 
            onClick={() => handleAction(false)}
            className="flex-1 py-5 rounded-2xl bg-white border border-red-100 text-red-500 font-medium hover:bg-red-50 transition-colors flex items-center justify-center gap-2"
          >
            <Undo2 size={18} />
            Forgot
          </button>
          <button 
            onClick={() => handleAction(true)}
            className="flex-1 py-5 rounded-2xl bg-green-500 text-white font-medium hover:bg-green-600 transition-all shadow-lg shadow-green-500/20 flex items-center justify-center gap-2"
          >
            <Check size={18} />
            Remembered
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

const CACHE_NAME = 'ebbflow-v1';
const ASSETS = [
  './',
  './index.html',
  './manifest.json',
  'https://cdn.tailwindcss.com',
  'https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600&display=swap'
];

self.addEventListener('install', (event) => {
  event.waitUntil(
    caches.open(CACHE_NAME).then((cache) => cache.addAll(ASSETS))
  );
});

self.addEventListener('fetch', (event) => {
  event.respondWith(
    caches.match(event.request).then((response) => {
      return response || fetch(event.request);
    })
  );
});

import React, { useState, useEffect, useCallback } from 'react';
