      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      phonetic: translationResult.phonetic,
