import React, { useState, useEffect, useCallback } from 'react';
import { Search, Brain, List, BarChart3, Plus, ChevronRight, Volume2, Trash2, Check, X, Undo2, Clock } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);

  // Load data
  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      try {
        setWords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse words", e);
      }
    }
  }, []);

  // Save data
  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
    } finally {
      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 0,
      createdAt: Date.now(),
      lastReviewDate: Date.now(),
      nextReviewDate: Date.now() + REVIEW_INTERVALS[0]
    };
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, 8) : 0;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: Date.now(),
          nextReviewDate: Date.now() + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const formatNextReview = (nextDate: number) => {
    const now = Date.now();
    const diff = nextDate - now;

    if (diff <= 0) return { text: '准好复习', color: 'text-red-500' };

    const mins = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (mins < 60) return { text: `${mins} 分钟后`, color: 'text-blue-500' };
    if (hours < 24) return { text: `${hours} 小时后`, color: 'text-blue-500' };
    return { text: `${days} 天后`, color: 'text-slate-400' };
  };

  const dueWords = words.filter(w => Date.now() >= w.nextReviewDate);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm selection:bg-blue-100">
      {/* Header with Safe Area padding */}
      <header className="px-6 pt-12 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-2xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-8 rounded-full"></span>
          EbbFlow
        </h1>
      </header>

      {/* Main Content */}
      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="Enter word or phrase..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button 
                  type="submit"
                  disabled={loading}
                  className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 hover:bg-blue-50 transition-colors"
                >
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-3xl p-6 shadow-xl shadow-slate-200/50 border border-slate-100 space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1">
                      <h3 className="text-xl font-semibold text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono tracking-wider">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-3 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>
                  <p className="text-slate-600 italic leading-relaxed text-sm bg-slate-50 p-4 rounded-xl">
                    "{translationResult.exampleSentence}"
                  </p>
                  <button 
                    onClick={addToMemory}
                    className="w-full py-4 rounded-2xl bg-blue-500 text-white font-semibold hover:bg-blue-600 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-500/25"
                  >
                    <Brain size={18} />
                    Add to Memory
                  </button>
                </div>
              )}
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between">
                 <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">Progress</h2>
                 <span className="text-[10px] text-blue-600 font-bold px-2 py-1 bg-blue-100/50 rounded-full">
                    {dueWords.length} DUE NOW
                 </span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm hover:border-blue-100 transition-colors">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">Vault</p>
                    <p className="text-3xl font-light text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm hover:border-green-100 transition-colors">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">Mastered</p>
                    <p className="text-3xl font-light text-green-500">{words.filter(w => w.stage === 8).length}</p>
                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400 mb-6">Your Library</h2>
            {words.length === 0 ? (
               <div className="text-center py-20 text-slate-300 font-light italic">Your memory vault is empty.</div>
            ) : (
              <div className="space-y-3">
                {words.map(w => {
                  const timeInfo = formatNextReview(w.nextReviewDate);
                  return (
                    <div key={w.id} className="bg-white p-5 rounded-2xl border border-slate-100 flex items-center justify-between group hover:shadow-md transition-all">
                      <div className="space-y-1">
                        <h4 className="font-medium text-slate-800">{w.original}</h4>
                        <div className="flex items-center gap-2">
                          <span className="text-xs text-slate-400">{w.translation}</span>
                          <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                          <div className="flex items-center gap-1.5">
                            <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-1.5 py-0.5 rounded uppercase tracking-tighter">ST {w.stage}</span>
                            <span className={`text-[10px] font-medium flex items-center gap-0.5 ${timeInfo.color}`}>
                              <Clock size={10} />
                              {timeInfo.text}
                            </span>
                          </div>
                        </div>
                      </div>
                      <button onClick={() => deleteWord(w.id)} className="p-2 text-slate-300 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-all">
                        <Trash2 size={18} />
                      </button>
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeView === View.STATS && (
           <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">Retention Matrix</h2>
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                <div className="flex flex-wrap gap-2 justify-center">
                  {Array.from({ length: 112 }).map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-3 h-3 rounded-[2px] ${i % 12 === 0 ? 'bg-blue-400' : (i % 8 === 0 ? 'bg-blue-200' : 'bg-slate-100')}`} 
                    />
                  ))}
                </div>
                <div className="mt-8 flex justify-between items-end">
                   <div>
                     <p className="text-2xl font-light text-slate-800">84%</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Efficiency</p>
                   </div>
                   <div className="text-right">
                     <p className="text-2xl font-light text-slate-800">12.4</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">New / Day</p>
                   </div>
                </div>
              </div>
           </div>
        )}
      </main>

      {/* Navigation - Bottom Padded for iOS safe area */}
      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] p-2 flex items-center gap-1 z-50">
        <NavButton active={activeView === View.HOME} onClick={() => setActiveView(View.HOME)} icon={<Search size={22} />} label="Explore" />
        <NavButton 
          active={activeView === View.REVIEW} 
          onClick={() => setActiveView(View.REVIEW)} 
          icon={<Brain size={22} />} 
          label="Review" 
          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={22} />} label="Library" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={22} />} label="Stats" />
      </nav>
    </div>
  );
};

