import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface TranslationResult {
  translation: string;
  definitionEn: string;
  phonetic: string;
  exampleSentence: string;
}

export const getTranslation = async (text: string): Promise<TranslationResult> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Act as an expert lexicographer. For the text "${text}":
    1. Translate to Chinese (if English) or English (if Chinese).
    2. Provide a clear, concise English definition (English-to-English).
    3. Provide IPA phonetic notation.
    4. Provide one natural, high-quality example sentence in English.

    Return the result in JSON format.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          translation: { type: Type.STRING },
          definitionEn: { type: Type.STRING, description: "English to English definition" },
          phonetic: { type: Type.STRING },
          exampleSentence: { type: Type.STRING, description: "Example sentence in English" },
        },
        required: ["translation", "definitionEn", "phonetic", "exampleSentence"]
      }
    }
  });

  return JSON.parse(response.text);
};

import React, { useState, useEffect } from 'react';
import { Search, Brain, List, BarChart3, Plus, Volume2, Trash2, Check, Clock, CalendarDays, ChevronDown, ChevronUp } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);
  const [expandedSchedule, setExpandedSchedule] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      try {
        setWords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse words", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
    } finally {
      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 0,
      createdAt: Date.now(),
      lastReviewDate: Date.now(),
      nextReviewDate: Date.now() + REVIEW_INTERVALS[0]
    };
    // Store additional meta like definitionEn in a persistent way if needed, 
    // for now we'll display it from the temporary result or extend Word type.
    // To keep it simple, we'll focus on the requested Library schedule.
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, 8) : 0;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: Date.now(),
          nextReviewDate: Date.now() + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const formatNextReview = (nextDate: number) => {
    const now = Date.now();
    const diff = nextDate - now;
    if (diff <= 0) return { text: '准备复习', color: 'text-red-500' };
    const mins = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    if (mins < 60) return { text: `${mins} 分钟后`, color: 'text-blue-500' };
    if (hours < 24) return { text: `${hours} 小时后`, color: 'text-blue-500' };
    return { text: `${days} 天后`, color: 'text-slate-400' };
  };

  const getIntervalLabel = (stage: number) => {
    const ms = REVIEW_INTERVALS[stage];
    if (ms === 0) return "立即";
    const mins = ms / (1000 * 60);
    if (mins < 60) return `${mins}分钟`;
    const hours = mins / 60;
    if (hours < 24) return `${hours}小时`;
    return `${hours / 24}天`;
  };

  const dueWords = words.filter(w => Date.now() >= w.nextReviewDate);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm selection:bg-blue-100">
      <header className="px-6 pt-12 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-2xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-8 rounded-full"></span>
          EbbFlow
        </h1>
      </header>

      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="输入单词或短语..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button type="submit" disabled={loading} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 transition-colors">
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-3xl p-6 shadow-xl shadow-slate-200/50 border border-slate-100 space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1 flex-1">
                      <h3 className="text-xl font-semibold text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono tracking-wider">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-3 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>

                  <div className="space-y-3 pt-2 border-t border-slate-50">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">English Definition</p>
                      <p className="text-sm text-slate-700 leading-relaxed font-medium">{translationResult.definitionEn}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Example</p>
                      <p className="text-slate-600 italic text-sm leading-relaxed bg-slate-50 p-3 rounded-xl border border-slate-100">
                        "{translationResult.exampleSentence}"
                      </p>
                    </div>
                  </div>

                  <button 
                    onClick={addToMemory}
