               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已收藏</p>
                    <p className="text-3xl font-light text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已精通</p>
                    <p className="text-3xl font-light text-green-500">{words.filter(w => w.stage === 8).length}</p>
                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400 mb-6">词汇库</h2>
            {words.length === 0 ? (
               <div className="text-center py-20 text-slate-300 font-light italic">记忆库为空</div>
            ) : (
              <div className="space-y-3">
                {words.map(w => {
                  const timeInfo = formatNextReview(w.nextReviewDate);
                  const isExpanded = expandedSchedule === w.id;
                  return (
                    <div key={w.id} className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm transition-all">
                      <div className="p-5 flex items-center justify-between group">
                        <div className="space-y-1">
                          <h4 className="font-medium text-slate-800">{w.original}</h4>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-400">{w.translation}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-1.5 py-0.5 rounded uppercase">ST {w.stage}</span>
                              <span className={`text-[10px] font-medium flex items-center gap-0.5 ${timeInfo.color}`}>
                                <Clock size={10} />
