                            <div className="relative pl-4 space-y-4 before:absolute before:left-1 before:top-1 before:bottom-1 before:w-px before:bg-slate-200">
                              {REVIEW_INTERVALS.map((interval, idx) => {
                                const isDone = idx < w.stage;
                                const isCurrent = idx === w.stage;
                                // Simplified calculation for display:
                                const estDate = new Date(w.createdAt + REVIEW_INTERVALS.slice(0, idx + 1).reduce((a, b) => a + b, 0));
                                return (
                                  <div key={idx} className="relative flex items-center justify-between text-[11px]">
