          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={22} />} label="词库" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={22} />} label="统计" />
      </nav>
    </div>
  );
};

