export default App;

export interface Word {
  id: string;
  original: string;
  translation: string;
  definitionEn?: string; // English-to-English definition
  phonetic?: string;
  exampleSentence: string;
  stage: number; // 0-8
  createdAt: number;
  nextReviewDate: number;
  lastReviewDate: number;
}

export const REVIEW_INTERVALS = [
  0,                  // Stage 0: Immediate
  5 * 60 * 1000,      // Stage 1: 5 mins
  30 * 60 * 1000,     // Stage 2: 30 mins
  12 * 60 * 60 * 1000,// Stage 3: 12 hours
  24 * 60 * 60 * 1000,// Stage 4: 1 day
  2 * 24 * 60 * 60 * 1000, // Stage 5: 2 days
  4 * 24 * 60 * 60 * 1000, // Stage 6: 4 days
  7 * 24 * 60 * 60 * 1000, // Stage 7: 7 days
  15 * 24 * 60 * 60 * 1000 // Stage 8: 15 days
];

export enum View {
  HOME = 'home',
  REVIEW = 'review',
  LIST = 'list',
  STATS = 'stats'
}

import React, { useState, useEffect } from 'react';
import { Search, Brain, List, BarChart3, Plus, Volume2, Trash2, Check, Clock, CalendarDays, Undo2 } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);
  const [expandedSchedule, setExpandedSchedule] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      try {
        setWords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse words", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
    } finally {
      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      definitionEn: translationResult.definitionEn,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 0,
      createdAt: Date.now(),
      lastReviewDate: Date.now(),
      nextReviewDate: Date.now() + REVIEW_INTERVALS[0]
    };
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, 8) : 0;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: Date.now(),
          nextReviewDate: Date.now() + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const formatNextReview = (nextDate: number) => {
    const now = Date.now();
    const diff = nextDate - now;
    if (diff <= 0) return { text: '准备复习', color: 'text-red-500' };
    const mins = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    if (mins < 60) return { text: `${mins} 分钟后`, color: 'text-blue-500' };
    if (hours < 24) return { text: `${hours} 小时后`, color: 'text-blue-500' };
    return { text: `${days} 天后`, color: 'text-slate-400' };
  };

  const getIntervalLabel = (stage: number) => {
    const ms = REVIEW_INTERVALS[stage];
    if (ms === 0) return "立即";
    const mins = ms / (1000 * 60);
    if (mins < 60) return `${mins}分钟`;
    const hours = mins / 60;
    if (hours < 24) return `${hours}小时`;
    return `${hours / 24}天`;
  };

  const dueWords = words.filter(w => Date.now() >= w.nextReviewDate);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm selection:bg-blue-100">
      <header className="px-6 pt-12 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-2xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-8 rounded-full"></span>
          EbbFlow
        </h1>
      </header>

      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="输入单词或短语..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button type="submit" disabled={loading} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 transition-colors">
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-3xl p-6 shadow-xl shadow-slate-200/50 border border-slate-100 space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1 flex-1">
                      <h3 className="text-xl font-semibold text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono tracking-wider">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-3 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>

                  <div className="space-y-3 pt-2 border-t border-slate-50">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">English Definition</p>
                      <p className="text-sm text-slate-700 leading-relaxed font-medium">{translationResult.definitionEn}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Example</p>
                      <p className="text-slate-600 italic text-sm leading-relaxed bg-slate-50 p-3 rounded-xl border border-slate-100">
                        "{translationResult.exampleSentence}"
                      </p>
                    </div>
                  </div>

                  <button 
                    onClick={addToMemory}
                    className="w-full py-4 rounded-2xl bg-blue-500 text-white font-semibold hover:bg-blue-600 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-500/25"
                  >
                    <Brain size={18} />
                    加入记忆库
                  </button>
                </div>
              )}
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between">
                 <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">学习进度</h2>
                 <span className="text-[10px] text-blue-600 font-bold px-2 py-1 bg-blue-100/50 rounded-full">
                    {dueWords.length} 个待复习
                 </span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已收藏</p>
                    <p className="text-3xl font-light text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已精通</p>
                    <p className="text-3xl font-light text-green-500">{words.filter(w => w.stage === 8).length}</p>
                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400 mb-6">词汇库</h2>
            {words.length === 0 ? (
               <div className="text-center py-20 text-slate-300 font-light italic">记忆库为空</div>
            ) : (
              <div className="space-y-3">
                {words.map(w => {
                  const timeInfo = formatNextReview(w.nextReviewDate);
                  const isExpanded = expandedSchedule === w.id;
                  return (
                    <div key={w.id} className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm transition-all">
                      <div className="p-5 flex items-center justify-between group">
                        <div className="space-y-1">
                          <h4 className="font-medium text-slate-800">{w.original}</h4>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-400">{w.translation}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-1.5 py-0.5 rounded uppercase">ST {w.stage}</span>
                              <span className={`text-[10px] font-medium flex items-center gap-0.5 ${timeInfo.color}`}>
                                <Clock size={10} />
                                {timeInfo.text}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button 
                            onClick={() => setExpandedSchedule(isExpanded ? null : w.id)}
                            className={`p-2 rounded-full transition-colors ${isExpanded ? 'bg-slate-100 text-slate-600' : 'text-slate-300 hover:text-blue-500 hover:bg-blue-50'}`}
                          >
                            <CalendarDays size={18} />
                          </button>
                          <button onClick={() => deleteWord(w.id)} className="p-2 text-slate-200 hover:text-red-500 transition-all">
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-5 pb-5 pt-2 bg-slate-50/50 border-t border-slate-50 animate-in slide-in-from-top-2">
                          <div className="space-y-3">
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">艾宾浩斯复习计划 (共8次)</p>
                            <div className="relative pl-4 space-y-4 before:absolute before:left-1 before:top-1 before:bottom-1 before:w-px before:bg-slate-200">
                              {REVIEW_INTERVALS.map((interval, idx) => {
                                const isDone = idx < w.stage;
                                const isCurrent = idx === w.stage;
                                const estDate = new Date(w.createdAt + REVIEW_INTERVALS.slice(0, idx + 1).reduce((a, b) => a + b, 0));
                                return (
                                  <div key={idx} className="relative flex items-center justify-between text-[11px]">
                                    <div className={`absolute -left-[15px] w-1.5 h-1.5 rounded-full z-10 ${isDone ? 'bg-green-500' : (isCurrent ? 'bg-blue-500 ring-4 ring-blue-100' : 'bg-slate-300')}`}></div>
                                    <span className={`${isDone ? 'text-slate-400 line-through' : (isCurrent ? 'text-blue-600 font-bold' : 'text-slate-500')}`}>
                                      阶段 {idx + 1} ({getIntervalLabel(idx)})
                                    </span>
                                    <span className="text-slate-400 font-mono">
                                      {estDate.toLocaleDateString()} {estDate.getHours()}:00
                                    </span>
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeView === View.STATS && (
           <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">记忆曲线分析</h2>
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                <div className="flex flex-wrap gap-2 justify-center">
                  {Array.from({ length: 112 }).map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-3 h-3 rounded-[2px] ${i % 12 === 0 ? 'bg-blue-400' : (i % 8 === 0 ? 'bg-blue-200' : 'bg-slate-100')}`} 
                    />
                  ))}
                </div>
                <div className="mt-8 flex justify-between items-end">
                   <div>
                     <p className="text-2xl font-light text-slate-800">84%</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">记忆留存率</p>
                   </div>
                   <div className="text-right">
                     <p className="text-2xl font-light text-slate-800">12.4</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">每日新词</p>
                   </div>
                </div>
              </div>
           </div>
        )}
      </main>

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] p-2 flex items-center gap-1 z-50">
        <NavButton active={activeView === View.HOME} onClick={() => setActiveView(View.HOME)} icon={<Search size={22} />} label="发现" />
        <NavButton 
          active={activeView === View.REVIEW} 
          onClick={() => setActiveView(View.REVIEW)} 
          icon={<Brain size={22} />} 
          label="复习" 
          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={22} />} label="词库" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={22} />} label="统计" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; badge?: number }> = ({ active, onClick, icon, label, badge }) => (
  <button 
    onClick={onClick}
    className={`relative px-5 py-3 rounded-[2rem] flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/40 scale-105' : 'text-slate-400 hover:bg-slate-50'}`}
  >
    {icon}
    <span className="text-[9px] font-bold tracking-widest uppercase">{label}</span>
    {badge !== undefined && !active && (
      <span className="absolute top-1.5 right-3 w-4 h-4 bg-red-500 text-white text-[9px] font-bold flex items-center justify-center rounded-full animate-pulse border-2 border-white">
        {badge}
      </span>
    )}
  </button>
);

const ReviewMode: React.FC<{ words: Word[]; onReview: (id: string, rem: boolean) => void; onSpeak: (t: string) => void }> = ({ words, onReview, onSpeak }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const currentWord = words[currentIndex];

  if (!currentWord) {
    return (
      <div className="flex flex-col items-center justify-center py-24 space-y-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-500 shadow-inner">
          <Check size={48} className="animate-bounce" />
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-light text-slate-800">暂无任务</h2>
          <p className="text-slate-400 max-w-[200px] mx-auto text-sm">您的记忆正处于艾宾浩斯曲线的理想位置。</p>
        </div>
      </div>
    );
  }

  const handleAction = (remembered: boolean) => {
    onReview(currentWord.id, remembered);
    setFlipped(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex justify-between items-center px-2">
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-blue-500"></span>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">阶段 {currentWord.stage}</span>
        </div>
        <span className="text-[10px] font-bold text-slate-300 bg-slate-100 px-2 py-0.5 rounded-full">{currentIndex + 1} / {words.length}</span>
      </div>

      <div onClick={() => setFlipped(!flipped)} className="relative h-[28rem] w-full perspective-1000 cursor-pointer active:scale-[0.99] transition-transform duration-200">
        <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${flipped ? 'rotate-y-180' : ''}`}>
          {/* Front: Question */}
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-center p-12 backface-hidden">
            <h3 className="text-4xl font-light text-slate-800 text-center leading-tight tracking-tight">{currentWord.original}</h3>
            <p className="mt-12 text-blue-400 text-[10px] font-bold uppercase tracking-[0.3em] flex items-center gap-2">点击翻面</p>
          </div>

          {/* Back: Details */}
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-start p-8 backface-hidden rotate-y-180 text-center overflow-y-auto">
            <div className="w-full space-y-5">
              <div className="space-y-1">
                <h3 className="text-2xl font-bold text-slate-800 leading-tight">{currentWord.translation}</h3>
                <p className="text-slate-400 font-mono text-xs tracking-wider uppercase">{currentWord.phonetic}</p>
              </div>

              <div className="h-px w-16 bg-slate-100 mx-auto"></div>

              {currentWord.definitionEn && (
                <div className="text-left">
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">English Definition</p>
                  <p className="text-sm text-slate-700 leading-snug font-medium italic">
                    {currentWord.definitionEn}
                  </p>
                </div>
              )}

              <div className="text-left bg-slate-50/80 p-4 rounded-2xl border border-slate-100">
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">Example</p>
                <p className="text-slate-600 italic text-sm leading-relaxed">
                  "{currentWord.exampleSentence}"
                </p>
              </div>

              <div className="flex justify-center pt-2">
                <button 
                  onClick={(e) => { e.stopPropagation(); onSpeak(currentWord.original); }} 
                  className="p-4 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors shadow-sm"
                >
                  <Volume2 size={24} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {flipped && (
        <div className="flex gap-4 animate-in slide-in-from-bottom-8 duration-500 ease-out">
          <button 
            onClick={() => handleAction(false)} 
            className="flex-1 py-6 rounded-[2rem] bg-white border border-red-100 text-red-500 font-bold uppercase tracking-widest text-[10px] hover:bg-red-50 transition-colors shadow-sm flex items-center justify-center gap-2"
          >
            <Undo2 size={16} />
            忘记了
          </button>
          <button 
            onClick={() => handleAction(true)} 
            className="flex-1 py-6 rounded-[2rem] bg-green-500 text-white font-bold uppercase tracking-widest text-[10px] hover:bg-green-600 transition-all shadow-xl shadow-green-500/30 flex items-center justify-center gap-2"
          >
            <Check size={16} />
            记住了
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

export interface Word {
  id: string;
  original: string;
  translation: string;
  definitionEn?: string; // English-to-English definition
  phonetic?: string;
  exampleSentence: string;
  stage: number; // 0-10
  createdAt: number;
  nextReviewDate: number;
  lastReviewDate: number;
}

export const REVIEW_INTERVALS = [
  0,                  // Stage 0: Immediate
  5 * 60 * 1000,      // Stage 1: 5 mins
  30 * 60 * 1000,     // Stage 2: 30 mins
  12 * 60 * 60 * 1000,// Stage 3: 12 hours
  24 * 60 * 60 * 1000,// Stage 4: 1 day
  2 * 24 * 60 * 60 * 1000, // Stage 5: 2 days
  4 * 24 * 60 * 60 * 1000, // Stage 6: 4 days
  7 * 24 * 60 * 60 * 1000, // Stage 7: 7 days
  15 * 24 * 60 * 60 * 1000, // Stage 8: 15 days
  30 * 24 * 60 * 60 * 1000, // Stage 9: 1 month (30 days)
  90 * 24 * 60 * 60 * 1000  // Stage 10: 3 months (90 days)
];

export enum View {
  HOME = 'home',
  REVIEW = 'review',
  LIST = 'list',
  STATS = 'stats'
}

import React, { useState, useEffect } from 'react';
import { Search, Brain, List, BarChart3, Plus, Volume2, Trash2, Check, Clock, CalendarDays, Undo2 } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);
  const [expandedSchedule, setExpandedSchedule] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      try {
        setWords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse words", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
    } finally {
      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const now = Date.now();
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      definitionEn: translationResult.definitionEn,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 1, // Start at stage 1 after adding
      createdAt: now,
      lastReviewDate: now,
      nextReviewDate: now + REVIEW_INTERVALS[1]
    };
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    const now = Date.now();
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, REVIEW_INTERVALS.length - 1) : 1;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: now,
          nextReviewDate: now + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const formatNextReview = (nextDate: number) => {
    const now = Date.now();
    const diff = nextDate - now;
    if (diff <= 0) return { text: '准备复习', color: 'text-red-500' };
    const mins = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));
    if (mins < 60) return { text: `${mins} 分钟后`, color: 'text-blue-500' };
    if (hours < 24) return { text: `${hours} 小时后`, color: 'text-blue-500' };
    return { text: `${days} 天后`, color: 'text-slate-400' };
  };

  const getIntervalLabel = (stage: number) => {
    const ms = REVIEW_INTERVALS[stage];
    if (ms === 0) return "立即";
    const mins = ms / (1000 * 60);
    if (mins < 60) return `${mins}分钟`;
    const hours = mins / 60;
    if (hours < 24) return `${hours}小时`;
    const days = hours / 24;
    if (days < 30) return `${days}天`;
    return `${Math.round(days / 30)}个月`;
  };

  const dueWords = words.filter(w => Date.now() >= w.nextReviewDate);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm selection:bg-blue-100">
      <header className="px-6 pt-12 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-2xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-8 rounded-full"></span>
          EbbFlow
        </h1>
      </header>

      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="输入单词或短语..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button type="submit" disabled={loading} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 transition-colors">
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-3xl p-6 shadow-xl shadow-slate-200/50 border border-slate-100 space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1 flex-1">
                      <h3 className="text-xl font-semibold text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono tracking-wider">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-3 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>

                  <div className="space-y-3 pt-2 border-t border-slate-50">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">English Definition</p>
                      <p className="text-sm text-slate-700 leading-relaxed font-medium">{translationResult.definitionEn}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Example</p>
                      <p className="text-slate-600 italic text-sm leading-relaxed bg-slate-50 p-3 rounded-xl border border-slate-100">
                        "{translationResult.exampleSentence}"
                      </p>
                    </div>
                  </div>

                  <button 
                    onClick={addToMemory}
                    className="w-full py-4 rounded-2xl bg-blue-500 text-white font-semibold hover:bg-blue-600 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-500/25"
                  >
                    <Brain size={18} />
                    加入记忆库
                  </button>
                </div>
              )}
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between">
                 <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">学习进度</h2>
                 <span className="text-[10px] text-blue-600 font-bold px-2 py-1 bg-blue-100/50 rounded-full">
                    {dueWords.length} 个待复习
                 </span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已收藏</p>
                    <p className="text-3xl font-light text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已精通</p>
                    <p className="text-3xl font-light text-green-500">{words.filter(w => w.stage === 10).length}</p>
                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400 mb-6">词汇库</h2>
            {words.length === 0 ? (
               <div className="text-center py-20 text-slate-300 font-light italic">记忆库为空</div>
            ) : (
              <div className="space-y-3">
                {words.map(w => {
                  const timeInfo = formatNextReview(w.nextReviewDate);
                  const isExpanded = expandedSchedule === w.id;
                  return (
                    <div key={w.id} className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm transition-all">
                      <div className="p-5 flex items-center justify-between group">
                        <div className="space-y-1">
                          <h4 className="font-medium text-slate-800">{w.original}</h4>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-400">{w.translation}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-1.5 py-0.5 rounded uppercase">ST {w.stage}</span>
                              <span className={`text-[10px] font-medium flex items-center gap-0.5 ${timeInfo.color}`}>
                                <Clock size={10} />
                                {timeInfo.text}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button 
                            onClick={() => setExpandedSchedule(isExpanded ? null : w.id)}
                            className={`p-2 rounded-full transition-colors ${isExpanded ? 'bg-slate-100 text-slate-600' : 'text-slate-300 hover:text-blue-500 hover:bg-blue-50'}`}
                          >
                            <CalendarDays size={18} />
                          </button>
                          <button onClick={() => deleteWord(w.id)} className="p-2 text-slate-200 hover:text-red-500 transition-all">
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-5 pb-5 pt-2 bg-slate-50/50 border-t border-slate-50 animate-in slide-in-from-top-2">
                          <div className="space-y-3">
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">艾宾浩斯计划 (10阶段动态推算)</p>
                            <div className="relative pl-4 space-y-4 before:absolute before:left-1 before:top-1 before:bottom-1 before:w-px before:bg-slate-200">
                              {REVIEW_INTERVALS.slice(1).map((interval, idx) => {
                                const stageNum = idx + 1;
                                const isDone = stageNum < w.stage;
                                const isCurrent = stageNum === w.stage;

                                // Dynamic prediction: 
                                // If done, show approximate past time or last review. 
                                // If future, show prediction from lastReviewDate.
                                let displayDate: Date;
                                if (isDone) {
                                  displayDate = new Date(w.createdAt); // Simplified for past logs
                                } else {
                                  // Predict based on when the previous stage was/is finished
                                  displayDate = new Date(w.lastReviewDate + (isCurrent ? 0 : interval));
                                }

                                return (
                                  <div key={idx} className="relative flex items-center justify-between text-[11px]">
                                    <div className={`absolute -left-[15px] w-1.5 h-1.5 rounded-full z-10 ${isDone ? 'bg-green-500' : (isCurrent ? 'bg-blue-500 ring-4 ring-blue-100' : 'bg-slate-300')}`}></div>
                                    <span className={`${isDone ? 'text-slate-400 line-through' : (isCurrent ? 'text-blue-600 font-bold' : 'text-slate-500')}`}>
                                      第{stageNum}次 ({getIntervalLabel(stageNum)})
                                    </span>
                                    <span className="text-slate-400 font-mono">
                                      {isCurrent ? '预计: ' : ''}
                                      {isCurrent ? formatNextReview(w.nextReviewDate).text : displayDate.toLocaleDateString()}
                                    </span>
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeView === View.STATS && (
           <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">记忆曲线分析</h2>
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                <div className="flex flex-wrap gap-2 justify-center">
                  {Array.from({ length: 112 }).map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-3 h-3 rounded-[2px] ${i % 12 === 0 ? 'bg-blue-400' : (i % 8 === 0 ? 'bg-blue-200' : 'bg-slate-100')}`} 
                    />
                  ))}
                </div>
                <div className="mt-8 flex justify-between items-end">
                   <div>
                     <p className="text-2xl font-light text-slate-800">84%</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">记忆留存率</p>
                   </div>
                   <div className="text-right">
                     <p className="text-2xl font-light text-slate-800">12.4</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">每日新词</p>
                   </div>
                </div>
              </div>
           </div>
        )}
      </main>

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] p-2 flex items-center gap-1 z-50">
        <NavButton active={activeView === View.HOME} onClick={() => setActiveView(View.HOME)} icon={<Search size={22} />} label="发现" />
        <NavButton 
          active={activeView === View.REVIEW} 
          onClick={() => setActiveView(View.REVIEW)} 
          icon={<Brain size={22} />} 
          label="复习" 
          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={22} />} label="词库" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={22} />} label="统计" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; badge?: number }> = ({ active, onClick, icon, label, badge }) => (
  <button 
    onClick={onClick}
    className={`relative px-5 py-3 rounded-[2rem] flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/40 scale-105' : 'text-slate-400 hover:bg-slate-50'}`}
  >
    {icon}
    <span className="text-[9px] font-bold tracking-widest uppercase">{label}</span>
    {badge !== undefined && !active && (
      <span className="absolute top-1.5 right-3 w-4 h-4 bg-red-500 text-white text-[9px] font-bold flex items-center justify-center rounded-full animate-pulse border-2 border-white">
        {badge}
      </span>
    )}
  </button>
);

const ReviewMode: React.FC<{ words: Word[]; onReview: (id: string, rem: boolean) => void; onSpeak: (t: string) => void }> = ({ words, onReview, onSpeak }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const currentWord = words[currentIndex];

  if (!currentWord) {
    return (
      <div className="flex flex-col items-center justify-center py-24 space-y-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-500 shadow-inner">
          <Check size={48} className="animate-bounce" />
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-light text-slate-800">暂无任务</h2>
          <p className="text-slate-400 max-w-[200px] mx-auto text-sm">您的记忆正处于艾宾浩斯曲线的理想位置。</p>
        </div>
      </div>
    );
  }

  const handleAction = (remembered: boolean) => {
    onReview(currentWord.id, remembered);
    setFlipped(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex justify-between items-center px-2">
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-blue-500"></span>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">阶段 {currentWord.stage} / 10</span>
        </div>
        <span className="text-[10px] font-bold text-slate-300 bg-slate-100 px-2 py-0.5 rounded-full">{currentIndex + 1} / {words.length}</span>
      </div>

      <div onClick={() => setFlipped(!flipped)} className="relative h-[28rem] w-full perspective-1000 cursor-pointer active:scale-[0.99] transition-transform duration-200">
        <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${flipped ? 'rotate-y-180' : ''}`}>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-center p-12 backface-hidden">
            <h3 className="text-4xl font-light text-slate-800 text-center leading-tight tracking-tight">{currentWord.original}</h3>
            <p className="mt-12 text-blue-400 text-[10px] font-bold uppercase tracking-[0.3em] flex items-center gap-2">点击翻面</p>
          </div>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-start p-8 backface-hidden rotate-y-180 text-center overflow-y-auto">
            <div className="w-full space-y-5">
              <div className="space-y-1">
                <h3 className="text-2xl font-bold text-slate-800 leading-tight">{currentWord.translation}</h3>
                <p className="text-slate-400 font-mono text-xs tracking-wider uppercase">{currentWord.phonetic}</p>
              </div>
              <div className="h-px w-16 bg-slate-100 mx-auto"></div>
              {currentWord.definitionEn && (
                <div className="text-left">
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">English Definition</p>
                  <p className="text-sm text-slate-700 leading-snug font-medium italic">{currentWord.definitionEn}</p>
                </div>
              )}
              <div className="text-left bg-slate-50/80 p-4 rounded-2xl border border-slate-100">
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">Example</p>
                <p className="text-slate-600 italic text-sm leading-relaxed">"{currentWord.exampleSentence}"</p>
              </div>
              <div className="flex justify-center pt-2">
                <button onClick={(e) => { e.stopPropagation(); onSpeak(currentWord.original); }} className="p-4 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors shadow-sm">
                  <Volume2 size={24} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {flipped && (
        <div className="flex gap-4 animate-in slide-in-from-bottom-8 duration-500 ease-out">
          <button onClick={() => handleAction(false)} className="flex-1 py-6 rounded-[2rem] bg-white border border-red-100 text-red-500 font-bold uppercase tracking-widest text-[10px] hover:bg-red-50 transition-colors shadow-sm flex items-center justify-center gap-2">
            <Undo2 size={16} />
            忘记了
          </button>
          <button onClick={() => handleAction(true)} className="flex-1 py-6 rounded-[2rem] bg-green-500 text-white font-bold uppercase tracking-widest text-[10px] hover:bg-green-600 transition-all shadow-xl shadow-green-500/30 flex items-center justify-center gap-2">
            <Check size={16} />
            记住了
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

export interface Word {
  id: string;
  original: string;
  translation: string;
  definitionEn?: string; // English-to-English definition
  phonetic?: string;
  exampleSentence: string;
  stage: number; // 0-11
  createdAt: number;
  nextReviewDate: number;
  lastReviewDate: number;
}

export const REVIEW_INTERVALS = [
  0,                  // Stage 0: Index placeholder
  5 * 1000,           // Stage 1: 5 seconds (Immediate reinforcement)
  5 * 60 * 1000,      // Stage 2: 5 mins
  30 * 60 * 1000,     // Stage 3: 30 mins
  12 * 60 * 60 * 1000,// Stage 4: 12 hours
  24 * 60 * 60 * 1000,// Stage 5: 1 day
  2 * 24 * 60 * 60 * 1000, // Stage 6: 2 days
  4 * 24 * 60 * 60 * 1000, // Stage 7: 4 days
  7 * 24 * 60 * 60 * 1000, // Stage 8: 7 days
  15 * 24 * 60 * 60 * 1000, // Stage 9: 15 days
  30 * 24 * 60 * 60 * 1000, // Stage 10: 1 month (30 days)
  90 * 24 * 60 * 60 * 1000  // Stage 11: 3 months (90 days)
];

export enum View {
  HOME = 'home',
  REVIEW = 'review',
  LIST = 'list',
  STATS = 'stats'
}

import React, { useState, useEffect } from 'react';
import { Search, Brain, List, BarChart3, Plus, Volume2, Trash2, Check, Clock, CalendarDays, Undo2 } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);
  const [expandedSchedule, setExpandedSchedule] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      try {
        setWords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse words", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
    } finally {
      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const now = Date.now();
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      definitionEn: translationResult.definitionEn,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 1, // Start at stage 1 (5s) after adding
      createdAt: now,
      lastReviewDate: now,
      nextReviewDate: now + REVIEW_INTERVALS[1]
    };
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    const now = Date.now();
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, REVIEW_INTERVALS.length - 1) : 1;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: now,
          nextReviewDate: now + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const formatNextReview = (nextDate: number) => {
    const now = Date.now();
    const diff = nextDate - now;
    if (diff <= 0) return { text: '准备复习', color: 'text-red-500' };
    const secs = Math.floor(diff / 1000);
    const mins = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (secs < 60) return { text: `${secs} 秒后`, color: 'text-orange-500 font-bold' };
    if (mins < 60) return { text: `${mins} 分钟后`, color: 'text-blue-500' };
    if (hours < 24) return { text: `${hours} 小时后`, color: 'text-blue-500' };
    return { text: `${days} 天后`, color: 'text-slate-400' };
  };

  const getIntervalLabel = (stage: number) => {
    const ms = REVIEW_INTERVALS[stage];
    if (ms === 0) return "立即";
    const secs = ms / 1000;
    if (secs < 60) return `${secs}秒`;
    const mins = secs / 60;
    if (mins < 60) return `${mins}分钟`;
    const hours = mins / 60;
    if (hours < 24) return `${hours}小时`;
    const days = hours / 24;
    if (days < 30) return `${days}天`;
    return `${Math.round(days / 30)}个月`;
  };

  const dueWords = words.filter(w => Date.now() >= w.nextReviewDate);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm selection:bg-blue-100">
      <header className="px-6 pt-12 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-2xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-8 rounded-full"></span>
          EbbFlow
        </h1>
      </header>

      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="输入单词或短语..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button type="submit" disabled={loading} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 transition-colors">
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-3xl p-6 shadow-xl shadow-slate-200/50 border border-slate-100 space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1 flex-1">
                      <h3 className="text-xl font-semibold text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono tracking-wider">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-3 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>

                  <div className="space-y-3 pt-2 border-t border-slate-50">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">English Definition</p>
                      <p className="text-sm text-slate-700 leading-relaxed font-medium">{translationResult.definitionEn}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Example</p>
                      <p className="text-slate-600 italic text-sm leading-relaxed bg-slate-50 p-3 rounded-xl border border-slate-100">
                        "{translationResult.exampleSentence}"
                      </p>
                    </div>
                  </div>

                  <button 
                    onClick={addToMemory}
                    className="w-full py-4 rounded-2xl bg-blue-500 text-white font-semibold hover:bg-blue-600 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-500/25"
                  >
                    <Brain size={18} />
                    加入记忆库
                  </button>
                </div>
              )}
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between">
                 <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">学习进度</h2>
                 <span className="text-[10px] text-blue-600 font-bold px-2 py-1 bg-blue-100/50 rounded-full">
                    {dueWords.length} 个待复习
                 </span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已收藏</p>
                    <p className="text-3xl font-light text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已精通</p>
                    <p className="text-3xl font-light text-green-500">{words.filter(w => w.stage === 11).length}</p>
                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400 mb-6">词汇库</h2>
            {words.length === 0 ? (
               <div className="text-center py-20 text-slate-300 font-light italic">记忆库为空</div>
            ) : (
              <div className="space-y-3">
                {words.map(w => {
                  const timeInfo = formatNextReview(w.nextReviewDate);
                  const isExpanded = expandedSchedule === w.id;
                  return (
                    <div key={w.id} className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm transition-all">
                      <div className="p-5 flex items-center justify-between group">
                        <div className="space-y-1">
                          <h4 className="font-medium text-slate-800">{w.original}</h4>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-400">{w.translation}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-1.5 py-0.5 rounded uppercase">ST {w.stage}</span>
                              <span className={`text-[10px] font-medium flex items-center gap-0.5 ${timeInfo.color}`}>
                                <Clock size={10} />
                                {timeInfo.text}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button 
                            onClick={() => setExpandedSchedule(isExpanded ? null : w.id)}
                            className={`p-2 rounded-full transition-colors ${isExpanded ? 'bg-slate-100 text-slate-600' : 'text-slate-300 hover:text-blue-500 hover:bg-blue-50'}`}
                          >
                            <CalendarDays size={18} />
                          </button>
                          <button onClick={() => deleteWord(w.id)} className="p-2 text-slate-200 hover:text-red-500 transition-all">
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-5 pb-5 pt-2 bg-slate-50/50 border-t border-slate-50 animate-in slide-in-from-top-2">
                          <div className="space-y-3">
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">艾宾浩斯计划 (11阶段动态)</p>
                            <div className="relative pl-4 space-y-4 before:absolute before:left-1 before:top-1 before:bottom-1 before:w-px before:bg-slate-200">
                              {REVIEW_INTERVALS.slice(1).map((interval, idx) => {
                                const stageNum = idx + 1;
                                const isDone = stageNum < w.stage;
                                const isCurrent = stageNum === w.stage;

                                let displayDate: Date;
                                if (isDone) {
                                  displayDate = new Date(w.createdAt); 
                                } else {
                                  displayDate = new Date(w.lastReviewDate + (isCurrent ? 0 : interval));
                                }

                                return (
                                  <div key={idx} className="relative flex items-center justify-between text-[11px]">
                                    <div className={`absolute -left-[15px] w-1.5 h-1.5 rounded-full z-10 ${isDone ? 'bg-green-500' : (isCurrent ? 'bg-blue-500 ring-4 ring-blue-100' : 'bg-slate-300')}`}></div>
                                    <span className={`${isDone ? 'text-slate-400 line-through' : (isCurrent ? 'text-blue-600 font-bold' : 'text-slate-500')}`}>
                                      第{stageNum}次 ({getIntervalLabel(stageNum)})
                                    </span>
                                    <span className="text-slate-400 font-mono">
                                      {isCurrent ? '预计: ' : ''}
                                      {isCurrent ? formatNextReview(w.nextReviewDate).text : displayDate.toLocaleDateString()}
                                    </span>
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeView === View.STATS && (
           <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">记忆曲线分析</h2>
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                <div className="flex flex-wrap gap-2 justify-center">
                  {Array.from({ length: 112 }).map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-3 h-3 rounded-[2px] ${i % 12 === 0 ? 'bg-blue-400' : (i % 8 === 0 ? 'bg-blue-200' : 'bg-slate-100')}`} 
                    />
                  ))}
                </div>
                <div className="mt-8 flex justify-between items-end">
                   <div>
                     <p className="text-2xl font-light text-slate-800">84%</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">记忆留存率</p>
                   </div>
                   <div className="text-right">
                     <p className="text-2xl font-light text-slate-800">12.4</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">每日新词</p>
                   </div>
                </div>
              </div>
           </div>
        )}
      </main>

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] p-2 flex items-center gap-1 z-50">
        <NavButton active={activeView === View.HOME} onClick={() => setActiveView(View.HOME)} icon={<Search size={22} />} label="发现" />
        <NavButton 
          active={activeView === View.REVIEW} 
          onClick={() => setActiveView(View.REVIEW)} 
          icon={<Brain size={22} />} 
          label="复习" 
          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={22} />} label="词库" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={22} />} label="统计" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; badge?: number }> = ({ active, onClick, icon, label, badge }) => (
  <button 
    onClick={onClick}
    className={`relative px-5 py-3 rounded-[2rem] flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/40 scale-105' : 'text-slate-400 hover:bg-slate-50'}`}
  >
    {icon}
    <span className="text-[9px] font-bold tracking-widest uppercase">{label}</span>
    {badge !== undefined && !active && (
      <span className="absolute top-1.5 right-3 w-4 h-4 bg-red-500 text-white text-[9px] font-bold flex items-center justify-center rounded-full animate-pulse border-2 border-white">
        {badge}
      </span>
    )}
  </button>
);

const ReviewMode: React.FC<{ words: Word[]; onReview: (id: string, rem: boolean) => void; onSpeak: (t: string) => void }> = ({ words, onReview, onSpeak }) => {
  const [currentIndex, setCurrentIndex] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const currentWord = words[currentIndex];

  if (!currentWord) {
    return (
      <div className="flex flex-col items-center justify-center py-24 space-y-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-500 shadow-inner">
          <Check size={48} className="animate-bounce" />
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-light text-slate-800">暂无任务</h2>
          <p className="text-slate-400 max-w-[200px] mx-auto text-sm">您的记忆正处于艾宾浩斯曲线的理想位置。</p>
        </div>
      </div>
    );
  }

  const handleAction = (remembered: boolean) => {
    onReview(currentWord.id, remembered);
    setFlipped(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex justify-between items-center px-2">
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-blue-500"></span>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">阶段 {currentWord.stage} / 11</span>
        </div>
        <span className="text-[10px] font-bold text-slate-300 bg-slate-100 px-2 py-0.5 rounded-full">{currentIndex + 1} / {words.length}</span>
      </div>

      <div onClick={() => setFlipped(!flipped)} className="relative h-[28rem] w-full perspective-1000 cursor-pointer active:scale-[0.99] transition-transform duration-200">
        <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${flipped ? 'rotate-y-180' : ''}`}>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-center p-12 backface-hidden">
            <h3 className="text-4xl font-light text-slate-800 text-center leading-tight tracking-tight">{currentWord.original}</h3>
            <p className="mt-12 text-blue-400 text-[10px] font-bold uppercase tracking-[0.3em] flex items-center gap-2">点击翻面</p>
          </div>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-start p-8 backface-hidden rotate-y-180 text-center overflow-y-auto">
            <div className="w-full space-y-5">
              <div className="space-y-1">
                <h3 className="text-2xl font-bold text-slate-800 leading-tight">{currentWord.translation}</h3>
                <p className="text-slate-400 font-mono text-xs tracking-wider uppercase">{currentWord.phonetic}</p>
              </div>
              <div className="h-px w-16 bg-slate-100 mx-auto"></div>
              {currentWord.definitionEn && (
                <div className="text-left">
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">English Definition</p>
                  <p className="text-sm text-slate-700 leading-snug font-medium italic">{currentWord.definitionEn}</p>
                </div>
              )}
              <div className="text-left bg-slate-50/80 p-4 rounded-2xl border border-slate-100">
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">Example</p>
                <p className="text-slate-600 italic text-sm leading-relaxed">"{currentWord.exampleSentence}"</p>
              </div>
              <div className="flex justify-center pt-2">
                <button onClick={(e) => { e.stopPropagation(); onSpeak(currentWord.original); }} className="p-4 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors shadow-sm">
                  <Volume2 size={24} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {flipped && (
        <div className="flex gap-4 animate-in slide-in-from-bottom-8 duration-500 ease-out">
          <button onClick={() => handleAction(false)} className="flex-1 py-6 rounded-[2rem] bg-white border border-red-100 text-red-500 font-bold uppercase tracking-widest text-[10px] hover:bg-red-50 transition-colors shadow-sm flex items-center justify-center gap-2">
            <Undo2 size={16} />
            忘记了
          </button>
          <button onClick={() => handleAction(true)} className="flex-1 py-6 rounded-[2rem] bg-green-500 text-white font-bold uppercase tracking-widest text-[10px] hover:bg-green-600 transition-all shadow-xl shadow-green-500/30 flex items-center justify-center gap-2">
            <Check size={16} />
            记住了
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Search, Brain, List, BarChart3, Plus, Volume2, Trash2, Check, Clock, CalendarDays, Undo2 } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);
  const [expandedSchedule, setExpandedSchedule] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      try {
        setWords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse words", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
    } finally {
      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const now = Date.now();
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      definitionEn: translationResult.definitionEn,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 1, // Start at stage 1 (5s) after adding
      createdAt: now,
      lastReviewDate: now,
      nextReviewDate: now + REVIEW_INTERVALS[1]
    };
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    const now = Date.now();
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, REVIEW_INTERVALS.length - 1) : 1;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: now,
          nextReviewDate: now + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const formatNextReview = (nextDate: number) => {
    const now = Date.now();
    const diff = nextDate - now;
    if (diff <= 0) return { text: '准备复习', color: 'text-red-500' };
    const secs = Math.floor(diff / 1000);
    const mins = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (secs < 60) return { text: `${secs} 秒后`, color: 'text-orange-500 font-bold' };
    if (mins < 60) return { text: `${mins} 分钟后`, color: 'text-blue-500' };
    if (hours < 24) return { text: `${hours} 小时后`, color: 'text-blue-500' };
    return { text: `${days} 天后`, color: 'text-slate-400' };
  };

  const getIntervalLabel = (stage: number) => {
    const ms = REVIEW_INTERVALS[stage];
    if (ms === 0) return "立即";
    const secs = ms / 1000;
    if (secs < 60) return `${secs}秒`;
    const mins = secs / 60;
    if (mins < 60) return `${mins}分钟`;
    const hours = mins / 60;
    if (hours < 24) return `${hours}小时`;
    const days = hours / 24;
    if (days < 30) return `${days}天`;
    return `${Math.round(days / 30)}个月`;
  };

  const dueWords = useMemo(() => words.filter(w => Date.now() >= w.nextReviewDate), [words]);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm selection:bg-blue-100">
      <header className="px-6 pt-12 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-2xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-8 rounded-full"></span>
          EbbFlow
        </h1>
      </header>

      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="输入单词或短语..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button type="submit" disabled={loading} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 transition-colors">
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-3xl p-6 shadow-xl shadow-slate-200/50 border border-slate-100 space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1 flex-1">
                      <h3 className="text-xl font-semibold text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono tracking-wider">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-3 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>

                  <div className="space-y-3 pt-2 border-t border-slate-50">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">English Definition</p>
                      <p className="text-sm text-slate-700 leading-relaxed font-medium">{translationResult.definitionEn}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Example</p>
                      <p className="text-slate-600 italic text-sm leading-relaxed bg-slate-50 p-3 rounded-xl border border-slate-100">
                        "{translationResult.exampleSentence}"
                      </p>
                    </div>
                  </div>

                  <button 
                    onClick={addToMemory}
                    className="w-full py-4 rounded-2xl bg-blue-500 text-white font-semibold hover:bg-blue-600 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-500/25"
                  >
                    <Brain size={18} />
                    加入记忆库
                  </button>
                </div>
              )}
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between">
                 <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">学习进度</h2>
                 <span className="text-[10px] text-blue-600 font-bold px-2 py-1 bg-blue-100/50 rounded-full">
                    {dueWords.length} 个待复习
                 </span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已收藏</p>
                    <p className="text-3xl font-light text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已精通</p>
                    <p className="text-3xl font-light text-green-500">{words.filter(w => w.stage === 11).length}</p>
                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400 mb-6">词汇库</h2>
            {words.length === 0 ? (
               <div className="text-center py-20 text-slate-300 font-light italic">记忆库为空</div>
            ) : (
              <div className="space-y-3">
                {words.map(w => {
                  const timeInfo = formatNextReview(w.nextReviewDate);
                  const isExpanded = expandedSchedule === w.id;
                  return (
                    <div key={w.id} className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm transition-all">
                      <div className="p-5 flex items-center justify-between group">
                        <div className="space-y-1">
                          <h4 className="font-medium text-slate-800">{w.original}</h4>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-400">{w.translation}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-1.5 py-0.5 rounded uppercase">ST {w.stage}</span>
                              <span className={`text-[10px] font-medium flex items-center gap-0.5 ${timeInfo.color}`}>
                                <Clock size={10} />
                                {timeInfo.text}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button 
                            onClick={() => setExpandedSchedule(isExpanded ? null : w.id)}
                            className={`p-2 rounded-full transition-colors ${isExpanded ? 'bg-slate-100 text-slate-600' : 'text-slate-300 hover:text-blue-500 hover:bg-blue-50'}`}
                          >
                            <CalendarDays size={18} />
                          </button>
                          <button onClick={() => deleteWord(w.id)} className="p-2 text-slate-200 hover:text-red-500 transition-all">
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-5 pb-5 pt-2 bg-slate-50/50 border-t border-slate-50 animate-in slide-in-from-top-2">
                          <div className="space-y-3">
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">艾宾浩斯计划 (11阶段动态)</p>
                            <div className="relative pl-4 space-y-4 before:absolute before:left-1 before:top-1 before:bottom-1 before:w-px before:bg-slate-200">
                              {REVIEW_INTERVALS.slice(1).map((interval, idx) => {
                                const stageNum = idx + 1;
                                const isDone = stageNum < w.stage;
                                const isCurrent = stageNum === w.stage;

                                let displayDate: Date;
                                if (isDone) {
                                  displayDate = new Date(w.createdAt); 
                                } else {
                                  displayDate = new Date(w.lastReviewDate + (isCurrent ? 0 : interval));
                                }

                                return (
                                  <div key={idx} className="relative flex items-center justify-between text-[11px]">
                                    <div className={`absolute -left-[15px] w-1.5 h-1.5 rounded-full z-10 ${isDone ? 'bg-green-500' : (isCurrent ? 'bg-blue-500 ring-4 ring-blue-100' : 'bg-slate-300')}`}></div>
                                    <span className={`${isDone ? 'text-slate-400 line-through' : (isCurrent ? 'text-blue-600 font-bold' : 'text-slate-500')}`}>
                                      第{stageNum}次 ({getIntervalLabel(stageNum)})
                                    </span>
                                    <span className="text-slate-400 font-mono">
                                      {isCurrent ? '预计: ' : ''}
                                      {isCurrent ? formatNextReview(w.nextReviewDate).text : displayDate.toLocaleDateString()}
                                    </span>
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeView === View.STATS && (
           <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">记忆曲线分析</h2>
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                <div className="flex flex-wrap gap-2 justify-center">
                  {Array.from({ length: 112 }).map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-3 h-3 rounded-[2px] ${i % 12 === 0 ? 'bg-blue-400' : (i % 8 === 0 ? 'bg-blue-200' : 'bg-slate-100')}`} 
                    />
                  ))}
                </div>
                <div className="mt-8 flex justify-between items-end">
                   <div>
                     <p className="text-2xl font-light text-slate-800">84%</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">记忆留存率</p>
                   </div>
                   <div className="text-right">
                     <p className="text-2xl font-light text-slate-800">12.4</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">每日新词</p>
                   </div>
                </div>
              </div>
           </div>
        )}
      </main>

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] p-2 flex items-center gap-1 z-50">
        <NavButton active={activeView === View.HOME} onClick={() => setActiveView(View.HOME)} icon={<Search size={22} />} label="发现" />
        <NavButton 
          active={activeView === View.REVIEW} 
          onClick={() => setActiveView(View.REVIEW)} 
          icon={<Brain size={22} />} 
          label="复习" 
          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={22} />} label="词库" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={22} />} label="统计" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; badge?: number }> = ({ active, onClick, icon, label, badge }) => (
  <button 
    onClick={onClick}
    className={`relative px-5 py-3 rounded-[2rem] flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/40 scale-105' : 'text-slate-400 hover:bg-slate-50'}`}
  >
    {icon}
    <span className="text-[9px] font-bold tracking-widest uppercase">{label}</span>
    {badge !== undefined && !active && (
      <span className="absolute top-1.5 right-3 w-4 h-4 bg-red-500 text-white text-[9px] font-bold flex items-center justify-center rounded-full animate-pulse border-2 border-white">
        {badge}
      </span>
    )}
  </button>
);

const ReviewMode: React.FC<{ words: Word[]; onReview: (id: string, rem: boolean) => void; onSpeak: (t: string) => void }> = ({ words, onReview, onSpeak }) => {
  // sessionQueue holds the IDs of words to review in this specific session.
  const [sessionQueue, setSessionQueue] = useState<string[]>([]);
  const [flipped, setFlipped] = useState(false);
  const [sessionCompletedCount, setSessionCompletedCount] = useState(0);

  // Initialize session queue when words prop changes and queue is empty
  useEffect(() => {
    if (words.length > 0 && sessionQueue.length === 0 && sessionCompletedCount === 0) {
      setSessionQueue(words.map(w => w.id));
    }
  }, [words, sessionQueue.length, sessionCompletedCount]);

  const currentId = sessionQueue[0];
  const currentWord = words.find(w => w.id === currentId);

  if (!currentWord || sessionQueue.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-24 space-y-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-500 shadow-inner">
          <Check size={48} className="animate-bounce" />
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-light text-slate-800">全部完成</h2>
          <p className="text-slate-400 max-w-[200px] mx-auto text-sm">
            {sessionCompletedCount > 0 ? `本次复习了 ${sessionCompletedCount} 个单词。` : "您的记忆正处于艾宾浩斯曲线的理想位置。"}
          </p>
        </div>
      </div>
    );
  }

  const handleAction = (remembered: boolean) => {
    if (remembered) {
      // Word is mastered for this session. Update global stage.
      onReview(currentWord.id, true);
      setSessionQueue(prev => prev.slice(1));
      setSessionCompletedCount(prev => prev + 1);
    } else {
      // Word is forgotten. Move to end of queue for re-review in this session.
      // We don't update the global stage yet (it stays in the 'forgotten' state until it's 'remembered' at least once in session)
      // Actually, to follow standard SRS: if forgotten once, stage resets to 1.
      onReview(currentWord.id, false); 
      setSessionQueue(prev => {
        const remaining = prev.slice(1);
        return [...remaining, currentId];
      });
    }
    setFlipped(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex justify-between items-center px-2">
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-blue-500"></span>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">阶段 {currentWord.stage} / 11</span>
        </div>
        <div className="flex flex-col items-end">
          <span className="text-[10px] font-bold text-slate-300 bg-slate-100 px-2 py-0.5 rounded-full">剩余 {sessionQueue.length} 个词</span>
        </div>
      </div>

      <div onClick={() => setFlipped(!flipped)} className="relative h-[28rem] w-full perspective-1000 cursor-pointer active:scale-[0.99] transition-transform duration-200">
        <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${flipped ? 'rotate-y-180' : ''}`}>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-center p-12 backface-hidden">
            <h3 className="text-4xl font-light text-slate-800 text-center leading-tight tracking-tight">{currentWord.original}</h3>
            <p className="mt-12 text-blue-400 text-[10px] font-bold uppercase tracking-[0.3em] flex items-center gap-2">点击翻面</p>
          </div>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-start p-8 backface-hidden rotate-y-180 text-center overflow-y-auto">
            <div className="w-full space-y-5">
              <div className="space-y-1">
                <h3 className="text-2xl font-bold text-slate-800 leading-tight">{currentWord.translation}</h3>
                <p className="text-slate-400 font-mono text-xs tracking-wider uppercase">{currentWord.phonetic}</p>
              </div>
              <div className="h-px w-16 bg-slate-100 mx-auto"></div>
              {currentWord.definitionEn && (
                <div className="text-left">
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">English Definition</p>
                  <p className="text-sm text-slate-700 leading-snug font-medium italic">{currentWord.definitionEn}</p>
                </div>
              )}
              <div className="text-left bg-slate-50/80 p-4 rounded-2xl border border-slate-100">
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">Example</p>
                <p className="text-slate-600 italic text-sm leading-relaxed">"{currentWord.exampleSentence}"</p>
              </div>
              <div className="flex justify-center pt-2">
                <button onClick={(e) => { e.stopPropagation(); onSpeak(currentWord.original); }} className="p-4 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors shadow-sm">
                  <Volume2 size={24} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {flipped && (
        <div className="flex gap-4 animate-in slide-in-from-bottom-8 duration-500 ease-out">
          <button onClick={() => handleAction(false)} className="flex-1 py-6 rounded-[2rem] bg-white border border-red-100 text-red-500 font-bold uppercase tracking-widest text-[10px] hover:bg-red-50 transition-colors shadow-sm flex items-center justify-center gap-2">
            <Undo2 size={16} />
            忘记了
          </button>
          <button onClick={() => handleAction(true)} className="flex-1 py-6 rounded-[2rem] bg-green-500 text-white font-bold uppercase tracking-widest text-[10px] hover:bg-green-600 transition-all shadow-xl shadow-green-500/30 flex items-center justify-center gap-2">
            <Check size={16} />
            记住了
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Search, Brain, List, BarChart3, Plus, Volume2, Trash2, Check, Clock, CalendarDays, Undo2 } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);
  const [expandedSchedule, setExpandedSchedule] = useState<string | null>(null);

  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      try {
        setWords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse words", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
    } finally {
      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const now = Date.now();
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      definitionEn: translationResult.definitionEn,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 1, // Start at stage 1 (5s) after adding
      createdAt: now,
      lastReviewDate: now,
      nextReviewDate: now + REVIEW_INTERVALS[1]
    };
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    const now = Date.now();
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, REVIEW_INTERVALS.length - 1) : 1;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: now,
          nextReviewDate: now + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const formatNextReview = (nextDate: number) => {
    const now = Date.now();
    const diff = nextDate - now;
    if (diff <= 0) return { text: '准备复习', color: 'text-red-500' };
    const secs = Math.floor(diff / 1000);
    const mins = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (secs < 60) return { text: `${secs} 秒后`, color: 'text-orange-500 font-bold' };
    if (mins < 60) return { text: `${mins} 分钟后`, color: 'text-blue-500' };
    if (hours < 24) return { text: `${hours} 小时后`, color: 'text-blue-500' };
    return { text: `${days} 天后`, color: 'text-slate-400' };
  };

  const getIntervalLabel = (stage: number) => {
    const ms = REVIEW_INTERVALS[stage];
    if (ms === 0) return "立即";
    const secs = ms / 1000;
    if (secs < 60) return `${secs}秒`;
    const mins = secs / 60;
    if (mins < 60) return `${mins}分钟`;
    const hours = mins / 60;
    if (hours < 24) return `${hours}小时`;
    const days = hours / 24;
    if (days < 30) return `${days}天`;
    return `${Math.round(days / 30)}个月`;
  };

  const dueWords = useMemo(() => words.filter(w => Date.now() >= w.nextReviewDate), [words]);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm selection:bg-blue-100">
      <header className="px-6 pt-12 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-2xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-8 rounded-full"></span>
          EbbFlow
        </h1>
      </header>

      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="输入单词或短语..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button type="submit" disabled={loading} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 transition-colors">
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-3xl p-6 shadow-xl shadow-slate-200/50 border border-slate-100 space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1 flex-1">
                      <h3 className="text-xl font-semibold text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono tracking-wider">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-3 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>

                  <div className="space-y-3 pt-2 border-t border-slate-50">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">English Definition</p>
                      <p className="text-sm text-slate-700 leading-relaxed font-medium">{translationResult.definitionEn}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Example</p>
                      <p className="text-slate-600 italic text-sm leading-relaxed bg-slate-50 p-3 rounded-xl border border-slate-100">
                        "{translationResult.exampleSentence}"
                      </p>
                    </div>
                  </div>

                  <button 
                    onClick={addToMemory}
                    className="w-full py-4 rounded-2xl bg-blue-500 text-white font-semibold hover:bg-blue-600 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-500/25"
                  >
                    <Brain size={18} />
                    加入记忆库
                  </button>
                </div>
              )}
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between">
                 <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">学习进度</h2>
                 <span className="text-[10px] text-blue-600 font-bold px-2 py-1 bg-blue-100/50 rounded-full">
                    {dueWords.length} 个待复习
                 </span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已收藏</p>
                    <p className="text-3xl font-light text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已精通</p>
                    <p className="text-3xl font-light text-green-500">{words.filter(w => w.stage === 11).length}</p>
                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400 mb-6">词汇库</h2>
            {words.length === 0 ? (
               <div className="text-center py-20 text-slate-300 font-light italic">记忆库为空</div>
            ) : (
              <div className="space-y-3">
                {words.map(w => {
                  const timeInfo = formatNextReview(w.nextReviewDate);
                  const isExpanded = expandedSchedule === w.id;
                  return (
                    <div key={w.id} className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm transition-all">
                      <div className="p-5 flex items-center justify-between group">
                        <div className="space-y-1">
                          <h4 className="font-medium text-slate-800">{w.original}</h4>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-400">{w.translation}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-1.5 py-0.5 rounded uppercase">ST {w.stage}</span>
                              <span className={`text-[10px] font-medium flex items-center gap-0.5 ${timeInfo.color}`}>
                                <Clock size={10} />
                                {timeInfo.text}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button 
                            onClick={() => setExpandedSchedule(isExpanded ? null : w.id)}
                            className={`p-2 rounded-full transition-colors ${isExpanded ? 'bg-slate-100 text-slate-600' : 'text-slate-300 hover:text-blue-500 hover:bg-blue-50'}`}
                          >
                            <CalendarDays size={18} />
                          </button>
                          <button onClick={() => deleteWord(w.id)} className="p-2 text-slate-200 hover:text-red-500 transition-all">
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-5 pb-5 pt-2 bg-slate-50/50 border-t border-slate-50 animate-in slide-in-from-top-2">
                          <div className="space-y-3">
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">艾宾浩斯计划 (11阶段动态)</p>
                            <div className="relative pl-4 space-y-4 before:absolute before:left-1 before:top-1 before:bottom-1 before:w-px before:bg-slate-200">
                              {REVIEW_INTERVALS.slice(1).map((interval, idx) => {
                                const stageNum = idx + 1;
                                const isDone = stageNum < w.stage;
                                const isCurrent = stageNum === w.stage;

                                let displayDate: Date;
                                if (isDone) {
                                  displayDate = new Date(w.createdAt); 
                                } else {
                                  displayDate = new Date(w.lastReviewDate + (isCurrent ? 0 : interval));
                                }

                                return (
                                  <div key={idx} className="relative flex items-center justify-between text-[11px]">
                                    <div className={`absolute -left-[15px] w-1.5 h-1.5 rounded-full z-10 ${isDone ? 'bg-green-500' : (isCurrent ? 'bg-blue-500 ring-4 ring-blue-100' : 'bg-slate-300')}`}></div>
                                    <span className={`${isDone ? 'text-slate-400 line-through' : (isCurrent ? 'text-blue-600 font-bold' : 'text-slate-500')}`}>
                                      第{stageNum}次 ({getIntervalLabel(stageNum)})
                                    </span>
                                    <span className="text-slate-400 font-mono">
                                      {isCurrent ? '预计: ' : ''}
                                      {isCurrent ? formatNextReview(w.nextReviewDate).text : displayDate.toLocaleDateString()}
                                    </span>
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeView === View.STATS && (
           <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">记忆曲线分析</h2>
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                <div className="flex flex-wrap gap-2 justify-center">
                  {Array.from({ length: 112 }).map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-3 h-3 rounded-[2px] ${i % 12 === 0 ? 'bg-blue-400' : (i % 8 === 0 ? 'bg-blue-200' : 'bg-slate-100')}`} 
                    />
                  ))}
                </div>
                <div className="mt-8 flex justify-between items-end">
                   <div>
                     <p className="text-2xl font-light text-slate-800">84%</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">记忆留存率</p>
                   </div>
                   <div className="text-right">
                     <p className="text-2xl font-light text-slate-800">12.4</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">每日新词</p>
                   </div>
                </div>
              </div>
           </div>
        )}
      </main>

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] p-2 flex items-center gap-1 z-50">
        <NavButton active={activeView === View.HOME} onClick={() => setActiveView(View.HOME)} icon={<Search size={22} />} label="发现" />
        <NavButton 
          active={activeView === View.REVIEW} 
          onClick={() => setActiveView(View.REVIEW)} 
          icon={<Brain size={22} />} 
          label="复习" 
          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={22} />} label="词库" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={22} />} label="统计" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; badge?: number }> = ({ active, onClick, icon, label, badge }) => (
  <button 
    onClick={onClick}
    className={`relative px-5 py-3 rounded-[2rem] flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/40 scale-105' : 'text-slate-400 hover:bg-slate-50'}`}
  >
    {icon}
    <span className="text-[9px] font-bold tracking-widest uppercase">{label}</span>
    {badge !== undefined && !active && (
      <span className="absolute top-1.5 right-3 w-4 h-4 bg-red-500 text-white text-[9px] font-bold flex items-center justify-center rounded-full animate-pulse border-2 border-white">
        {badge}
      </span>
    )}
  </button>
);

const ReviewMode: React.FC<{ words: Word[]; onReview: (id: string, rem: boolean) => void; onSpeak: (t: string) => void }> = ({ words, onReview, onSpeak }) => {
  const [sessionQueue, setSessionQueue] = useState<string[]>([]);
  const [flipped, setFlipped] = useState(false);
  const [sessionCompletedCount, setSessionCompletedCount] = useState(0);

  useEffect(() => {
    if (words.length > 0 && sessionQueue.length === 0 && sessionCompletedCount === 0) {
      setSessionQueue(words.map(w => w.id));
    }
  }, [words]);

  const currentId = sessionQueue[0];
  const currentWord = words.find(w => w.id === currentId);

  if (!currentWord || sessionQueue.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-24 space-y-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-500 shadow-inner">
          <Check size={48} className="animate-bounce" />
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-light text-slate-800">全部完成</h2>
          <p className="text-slate-400 max-w-[200px] mx-auto text-sm">
            {sessionCompletedCount > 0 ? `本次复习了 ${sessionCompletedCount} 个单词。` : "您的记忆库现在非常牢固。"}
          </p>
        </div>
      </div>
    );
  }

  const handleAction = (remembered: boolean) => {
    if (remembered) {
      // MASTERED: Update state to next stage and remove from session
      onReview(currentWord.id, true);
      setSessionQueue(prev => prev.slice(1));
      setSessionCompletedCount(prev => prev + 1);
    } else {
      // FORGOTTEN: Reset global stage to 1 and push to end of current session queue
      onReview(currentWord.id, false);
      setSessionQueue(prev => {
        const remaining = prev.slice(1);
        return [...remaining, currentId]; // Move to back of the loop
      });
    }
    setFlipped(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex justify-between items-center px-2">
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-blue-500"></span>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">阶段 {currentWord.stage} / 11</span>
        </div>
        <div className="flex flex-col items-end">
          <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-2 py-0.5 rounded-full tracking-wider">剩余 {sessionQueue.length} 个词</span>
        </div>
      </div>

      <div onClick={() => setFlipped(!flipped)} className="relative h-[28rem] w-full perspective-1000 cursor-pointer active:scale-[0.99] transition-transform duration-200">
        <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${flipped ? 'rotate-y-180' : ''}`}>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-center p-12 backface-hidden">
            <h3 className="text-4xl font-light text-slate-800 text-center leading-tight tracking-tight">{currentWord.original}</h3>
            <p className="mt-12 text-blue-400 text-[10px] font-bold uppercase tracking-[0.3em] flex items-center gap-2">点击翻面查看翻译</p>
          </div>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-start p-8 backface-hidden rotate-y-180 text-center overflow-y-auto">
            <div className="w-full space-y-5">
              <div className="space-y-1">
                <h3 className="text-2xl font-bold text-slate-800 leading-tight">{currentWord.translation}</h3>
                <p className="text-slate-400 font-mono text-xs tracking-wider uppercase">{currentWord.phonetic}</p>
              </div>
              <div className="h-px w-16 bg-slate-100 mx-auto"></div>
              {currentWord.definitionEn && (
                <div className="text-left">
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">English Definition</p>
                  <p className="text-sm text-slate-700 leading-snug font-medium italic">{currentWord.definitionEn}</p>
                </div>
              )}
              <div className="text-left bg-slate-50/80 p-4 rounded-2xl border border-slate-100">
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">Example</p>
                <p className="text-slate-600 italic text-sm leading-relaxed">"{currentWord.exampleSentence}"</p>
              </div>
              <div className="flex justify-center pt-2">
                <button onClick={(e) => { e.stopPropagation(); onSpeak(currentWord.original); }} className="p-4 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors shadow-sm">
                  <Volume2 size={24} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {flipped && (
        <div className="flex gap-4 animate-in slide-in-from-bottom-8 duration-500 ease-out">
          <button onClick={() => handleAction(false)} className="flex-1 py-6 rounded-[2rem] bg-white border border-red-100 text-red-500 font-bold uppercase tracking-widest text-[10px] hover:bg-red-50 transition-colors shadow-sm flex items-center justify-center gap-2 group">
            <Undo2 size={16} className="group-active:-rotate-45 transition-transform" />
            忘记了 (循环)
          </button>
          <button onClick={() => handleAction(true)} className="flex-1 py-6 rounded-[2rem] bg-green-500 text-white font-bold uppercase tracking-widest text-[10px] hover:bg-green-600 transition-all shadow-xl shadow-green-500/30 flex items-center justify-center gap-2 group">
            <Check size={16} className="group-active:scale-125 transition-transform" />
            记住了 (学会)
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Search, Brain, List, BarChart3, Plus, Volume2, Trash2, Check, Clock, CalendarDays, Undo2 } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);
  const [expandedSchedule, setExpandedSchedule] = useState<string | null>(null);
  const [now, setNow] = useState(Date.now());

  // Update current time every second to auto-refresh "due" status
  useEffect(() => {
    const timer = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      try {
        setWords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse words", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
    } finally {
      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const timestamp = Date.now();
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      definitionEn: translationResult.definitionEn,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 1, 
      createdAt: timestamp,
      lastReviewDate: timestamp,
      nextReviewDate: timestamp + REVIEW_INTERVALS[1]
    };
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    const timestamp = Date.now();
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, REVIEW_INTERVALS.length - 1) : 1;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: timestamp,
          nextReviewDate: timestamp + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const formatNextReview = (nextDate: number) => {
    const diff = nextDate - now;
    if (diff <= 0) return { text: '准备复习', color: 'text-red-500' };
    const secs = Math.floor(diff / 1000);
    const mins = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (secs < 60) return { text: `${secs} 秒后`, color: 'text-orange-500 font-bold' };
    if (mins < 60) return { text: `${mins} 分钟后`, color: 'text-blue-500' };
    if (hours < 24) return { text: `${hours} 小时后`, color: 'text-blue-500' };
    return { text: `${days} 天后`, color: 'text-slate-400' };
  };

  const getIntervalLabel = (stage: number) => {
    const ms = REVIEW_INTERVALS[stage];
    if (ms === 0) return "立即";
    const secs = ms / 1000;
    if (secs < 60) return `${secs}秒`;
    const mins = secs / 60;
    if (mins < 60) return `${mins}分钟`;
    const hours = mins / 60;
    if (hours < 24) return `${hours}小时`;
    const days = hours / 24;
    if (days < 30) return `${days}天`;
    return `${Math.round(days / 30)}个月`;
  };

  const dueWords = useMemo(() => words.filter(w => now >= w.nextReviewDate), [words, now]);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm selection:bg-blue-100">
      <header className="px-6 pt-12 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-2xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-8 rounded-full"></span>
          EbbFlow
        </h1>
      </header>

      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="输入单词或短语..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button type="submit" disabled={loading} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 transition-colors">
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-3xl p-6 shadow-xl shadow-slate-200/50 border border-slate-100 space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1 flex-1">
                      <h3 className="text-xl font-semibold text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono tracking-wider">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-3 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>

                  <div className="space-y-3 pt-2 border-t border-slate-50">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">English Definition</p>
                      <p className="text-sm text-slate-700 leading-relaxed font-medium">{translationResult.definitionEn}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Example</p>
                      <p className="text-slate-600 italic text-sm leading-relaxed bg-slate-50 p-3 rounded-xl border border-slate-100">
                        "{translationResult.exampleSentence}"
                      </p>
                    </div>
                  </div>

                  <button 
                    onClick={addToMemory}
                    className="w-full py-4 rounded-2xl bg-blue-500 text-white font-semibold hover:bg-blue-600 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-500/25"
                  >
                    <Brain size={18} />
                    加入记忆库
                  </button>
                </div>
              )}
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between">
                 <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">学习进度</h2>
                 <span className="text-[10px] text-blue-600 font-bold px-2 py-1 bg-blue-100/50 rounded-full">
                    {dueWords.length} 个待复习
                 </span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已收藏</p>
                    <p className="text-3xl font-light text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">已精通</p>
                    <p className="text-3xl font-light text-green-500">{words.filter(w => w.stage === 11).length}</p>
                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400 mb-6">词汇库</h2>
            {words.length === 0 ? (
               <div className="text-center py-20 text-slate-300 font-light italic">记忆库为空</div>
            ) : (
              <div className="space-y-3">
                {words.map(w => {
                  const timeInfo = formatNextReview(w.nextReviewDate);
                  const isExpanded = expandedSchedule === w.id;
                  return (
                    <div key={w.id} className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm transition-all">
                      <div className="p-5 flex items-center justify-between group">
                        <div className="space-y-1">
                          <h4 className="font-medium text-slate-800">{w.original}</h4>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-400">{w.translation}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-1.5 py-0.5 rounded uppercase">ST {w.stage}</span>
                              <span className={`text-[10px] font-medium flex items-center gap-0.5 ${timeInfo.color}`}>
                                <Clock size={10} />
                                {timeInfo.text}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button 
                            onClick={() => setExpandedSchedule(isExpanded ? null : w.id)}
                            className={`p-2 rounded-full transition-colors ${isExpanded ? 'bg-slate-100 text-slate-600' : 'text-slate-300 hover:text-blue-500 hover:bg-blue-50'}`}
                          >
                            <CalendarDays size={18} />
                          </button>
                          <button onClick={() => deleteWord(w.id)} className="p-2 text-slate-200 hover:text-red-500 transition-all">
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-5 pb-5 pt-2 bg-slate-50/50 border-t border-slate-50 animate-in slide-in-from-top-2">
                          <div className="space-y-3">
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">艾宾浩斯计划 (11阶段动态)</p>
                            <div className="relative pl-4 space-y-4 before:absolute before:left-1 before:top-1 before:bottom-1 before:w-px before:bg-slate-200">
                              {REVIEW_INTERVALS.slice(1).map((interval, idx) => {
                                const stageNum = idx + 1;
                                const isDone = stageNum < w.stage;
                                const isCurrent = stageNum === w.stage;

                                let displayDate: Date;
                                if (isDone) {
                                  displayDate = new Date(w.createdAt); 
                                } else {
                                  displayDate = new Date(w.lastReviewDate + (isCurrent ? 0 : interval));
                                }

                                return (
                                  <div key={idx} className="relative flex items-center justify-between text-[11px]">
                                    <div className={`absolute -left-[15px] w-1.5 h-1.5 rounded-full z-10 ${isDone ? 'bg-green-500' : (isCurrent ? 'bg-blue-500 ring-4 ring-blue-100' : 'bg-slate-300')}`}></div>
                                    <span className={`${isDone ? 'text-slate-400 line-through' : (isCurrent ? 'text-blue-600 font-bold' : 'text-slate-500')}`}>
                                      第{stageNum}次 ({getIntervalLabel(stageNum)})
                                    </span>
                                    <span className="text-slate-400 font-mono">
                                      {isCurrent ? '预计: ' : ''}
                                      {isCurrent ? formatNextReview(w.nextReviewDate).text : displayDate.toLocaleDateString()}
                                    </span>
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeView === View.STATS && (
           <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">记忆曲线分析</h2>
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                <div className="flex flex-wrap gap-2 justify-center">
                  {Array.from({ length: 112 }).map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-3 h-3 rounded-[2px] ${i % 12 === 0 ? 'bg-blue-400' : (i % 8 === 0 ? 'bg-blue-200' : 'bg-slate-100')}`} 
                    />
                  ))}
                </div>
                <div className="mt-8 flex justify-between items-end">
                   <div>
                     <p className="text-2xl font-light text-slate-800">84%</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">记忆留存率</p>
                   </div>
                   <div className="text-right">
                     <p className="text-2xl font-light text-slate-800">12.4</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">每日新词</p>
                   </div>
                </div>
              </div>
           </div>
        )}
      </main>

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] p-2 flex items-center gap-1 z-50">
        <NavButton active={activeView === View.HOME} onClick={() => setActiveView(View.HOME)} icon={<Search size={22} />} label="发现" />
        <NavButton 
          active={activeView === View.REVIEW} 
          onClick={() => setActiveView(View.REVIEW)} 
          icon={<Brain size={22} />} 
          label="复习" 
          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={22} />} label="词库" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={22} />} label="统计" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; badge?: number }> = ({ active, onClick, icon, label, badge }) => (
  <button 
    onClick={onClick}
    className={`relative px-5 py-3 rounded-[2rem] flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/40 scale-105' : 'text-slate-400 hover:bg-slate-50'}`}
  >
    {icon}
    <span className="text-[9px] font-bold tracking-widest uppercase">{label}</span>
    {badge !== undefined && !active && (
      <span className="absolute top-1.5 right-3 w-4 h-4 bg-red-500 text-white text-[9px] font-bold flex items-center justify-center rounded-full animate-pulse border-2 border-white">
        {badge}
      </span>
    )}
  </button>
);

const ReviewMode: React.FC<{ words: Word[]; onReview: (id: string, rem: boolean) => void; onSpeak: (t: string) => void }> = ({ words, onReview, onSpeak }) => {
  // Directly initialize state from props to prevent initial flicker
  const [sessionQueue, setSessionQueue] = useState<string[]>(() => words.map(w => w.id));
  const [flipped, setFlipped] = useState(false);
  const [sessionCompletedCount, setSessionCompletedCount] = useState(0);

  // Still need this for when words list actually changes via background timer
  useEffect(() => {
    if (words.length > 0 && sessionQueue.length === 0 && sessionCompletedCount === 0) {
      setSessionQueue(words.map(w => w.id));
    }
  }, [words, sessionCompletedCount, sessionQueue.length]);

  const currentId = sessionQueue[0];
  const currentWord = words.find(w => w.id === currentId);

  // If we had words to start with but they are all gone now
  if (!currentWord || sessionQueue.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-24 space-y-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-500 shadow-inner">
          <Check size={48} className="animate-bounce" />
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-light text-slate-800">全部完成</h2>
          <p className="text-slate-400 max-w-[200px] mx-auto text-sm">
            {sessionCompletedCount > 0 ? `本次复习了 ${sessionCompletedCount} 个单词。` : "您的记忆库现在非常牢固。"}
          </p>
        </div>
      </div>
    );
  }

  const handleAction = (remembered: boolean) => {
    if (remembered) {
      onReview(currentWord.id, true);
      setSessionQueue(prev => prev.slice(1));
      setSessionCompletedCount(prev => prev + 1);
    } else {
      onReview(currentWord.id, false);
      setSessionQueue(prev => {
        const remaining = prev.slice(1);
        return [...remaining, currentId]; 
      });
    }
    setFlipped(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex justify-between items-center px-2">
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-blue-500"></span>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">阶段 {currentWord.stage} / 11</span>
        </div>
        <div className="flex flex-col items-end">
          <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-2 py-0.5 rounded-full tracking-wider">剩余 {sessionQueue.length} 个词</span>
        </div>
      </div>

      <div onClick={() => setFlipped(!flipped)} className="relative h-[28rem] w-full perspective-1000 cursor-pointer active:scale-[0.99] transition-transform duration-200">
        <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${flipped ? 'rotate-y-180' : ''}`}>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-center p-12 backface-hidden">
            <h3 className="text-4xl font-light text-slate-800 text-center leading-tight tracking-tight">{currentWord.original}</h3>
            <p className="mt-12 text-blue-400 text-[10px] font-bold uppercase tracking-[0.3em] flex items-center gap-2">点击翻面查看翻译</p>
          </div>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-start p-8 backface-hidden rotate-y-180 text-center overflow-y-auto">
            <div className="w-full space-y-5">
              <div className="space-y-1">
                <h3 className="text-2xl font-bold text-slate-800 leading-tight">{currentWord.translation}</h3>
                <p className="text-slate-400 font-mono text-xs tracking-wider uppercase">{currentWord.phonetic}</p>
              </div>
              <div className="h-px w-16 bg-slate-100 mx-auto"></div>
              {currentWord.definitionEn && (
                <div className="text-left">
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">English Definition</p>
                  <p className="text-sm text-slate-700 leading-snug font-medium italic">{currentWord.definitionEn}</p>
                </div>
              )}
              <div className="text-left bg-slate-50/80 p-4 rounded-2xl border border-slate-100">
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">Example</p>
                <p className="text-slate-600 italic text-sm leading-relaxed">"{currentWord.exampleSentence}"</p>
              </div>
              <div className="flex justify-center pt-2">
                <button onClick={(e) => { e.stopPropagation(); onSpeak(currentWord.original); }} className="p-4 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors shadow-sm">
                  <Volume2 size={24} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {flipped && (
        <div className="flex gap-4 animate-in slide-in-from-bottom-8 duration-500 ease-out">
          <button onClick={() => handleAction(false)} className="flex-1 py-6 rounded-[2rem] bg-white border border-red-100 text-red-500 font-bold uppercase tracking-widest text-[10px] hover:bg-red-50 transition-colors shadow-sm flex items-center justify-center gap-2 group">
            <Undo2 size={16} className="group-active:-rotate-45 transition-transform" />
            忘记了 (循环)
          </button>
          <button onClick={() => handleAction(true)} className="flex-1 py-6 rounded-[2rem] bg-green-500 text-white font-bold uppercase tracking-widest text-[10px] hover:bg-green-600 transition-all shadow-xl shadow-green-500/30 flex items-center justify-center gap-2 group">
            <Check size={16} className="group-active:scale-125 transition-transform" />
            记住了 (学会)
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Search, Brain, List, BarChart3, Plus, Volume2, Trash2, Check, Clock, CalendarDays, Undo2 } from 'lucide-react';
import { Word, View, REVIEW_INTERVALS } from './types';
import { getTranslation } from './geminiService';

const App: React.FC = () => {
  const [activeView, setActiveView] = useState<View>(View.HOME);
  const [words, setWords] = useState<Word[]>([]);
  const [inputText, setInputText] = useState('');
  const [loading, setLoading] = useState(false);
  const [translationResult, setTranslationResult] = useState<any>(null);
  const [expandedSchedule, setExpandedSchedule] = useState<string | null>(null);
  const [now, setNow] = useState(Date.now());

  // Update current time every second to auto-refresh "due" status
  useEffect(() => {
    const timer = setInterval(() => setNow(Date.now()), 1000);
    return () => clearInterval(timer);
  }, []);

  useEffect(() => {
    const saved = localStorage.getItem('ebbflow_words');
    if (saved) {
      try {
        setWords(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to parse words", e);
      }
    }
  }, []);

  useEffect(() => {
    localStorage.setItem('ebbflow_words', JSON.stringify(words));
  }, [words]);

  const handleTranslate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    setLoading(true);
    try {
      const result = await getTranslation(inputText);
      setTranslationResult(result);
    } catch (error) {
      console.error("Translation failed", error);
    } finally {
      setLoading(false);
    }
  };

  const addToMemory = () => {
    if (!translationResult) return;
    const timestamp = Date.now();
    const newWord: Word = {
      id: Math.random().toString(36).substr(2, 9),
      original: inputText,
      translation: translationResult.translation,
      definitionEn: translationResult.definitionEn,
      phonetic: translationResult.phonetic,
      exampleSentence: translationResult.exampleSentence,
      stage: 1, 
      createdAt: timestamp,
      lastReviewDate: timestamp,
      nextReviewDate: timestamp + REVIEW_INTERVALS[1]
    };
    setWords(prev => [newWord, ...prev]);
    setInputText('');
    setTranslationResult(null);
  };

  const deleteWord = (id: string) => {
    setWords(prev => prev.filter(w => w.id !== id));
  };

  const updateWordStage = (id: string, remembered: boolean) => {
    const timestamp = Date.now();
    setWords(prev => prev.map(w => {
      if (w.id === id) {
        const nextStage = remembered ? Math.min(w.stage + 1, REVIEW_INTERVALS.length - 1) : 1;
        return {
          ...w,
          stage: nextStage,
          lastReviewDate: timestamp,
          nextReviewDate: timestamp + REVIEW_INTERVALS[nextStage]
        };
      }
      return w;
    }));
  };

  const speak = (text: string) => {
    const utterance = new SpeechSynthesisUtterance(text);
    window.speechSynthesis.speak(utterance);
  };

  const formatNextReview = (nextDate: number) => {
    const diff = nextDate - now;
    if (diff <= 0) return { text: 'Ready', color: 'text-red-500' };
    const secs = Math.floor(diff / 1000);
    const mins = Math.floor(diff / (1000 * 60));
    const hours = Math.floor(diff / (1000 * 60 * 60));
    const days = Math.floor(diff / (1000 * 60 * 60 * 24));

    if (secs < 60) return { text: `in ${secs}s`, color: 'text-orange-500 font-bold' };
    if (mins < 60) return { text: `in ${mins}m`, color: 'text-blue-500' };
    if (hours < 24) return { text: `in ${hours}h`, color: 'text-blue-500' };
    return { text: `in ${days}d`, color: 'text-slate-400' };
  };

  const getIntervalLabel = (stage: number) => {
    const ms = REVIEW_INTERVALS[stage];
    if (ms === 0) return "Instant";
    const secs = ms / 1000;
    if (secs < 60) return `${secs}s`;
    const mins = secs / 60;
    if (mins < 60) return `${mins}m`;
    const hours = mins / 60;
    if (hours < 24) return `${hours}h`;
    const days = hours / 24;
    if (days < 30) return `${days}d`;
    return `${Math.round(days / 30)}mo`;
  };

  const dueWords = useMemo(() => words.filter(w => now >= w.nextReviewDate), [words, now]);

  return (
    <div className="min-h-screen max-w-lg mx-auto bg-slate-50 flex flex-col shadow-sm selection:bg-blue-100">
      <header className="px-6 pt-12 pb-4 bg-white/50 backdrop-blur-md sticky top-0 z-10 border-b border-slate-100">
        <h1 className="text-xl font-light tracking-tight text-slate-800 flex items-center gap-2">
          <span className="bg-blue-500 w-2 h-7 rounded-full"></span>
          Elsa’s English Teacher
        </h1>
      </header>

      <main className="flex-1 px-6 py-6 overflow-y-auto pb-32">
        {activeView === View.HOME && (
          <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-500">
            <section className="space-y-4">
              <form onSubmit={handleTranslate} className="relative group">
                <input
                  type="text"
                  value={inputText}
                  onChange={(e) => setInputText(e.target.value)}
                  placeholder="Type a word or phrase..."
                  className="w-full h-16 px-6 pr-14 rounded-2xl bg-white border border-slate-200 focus:outline-none focus:ring-4 focus:ring-blue-500/10 focus:border-blue-400 transition-all text-lg font-light shadow-sm"
                />
                <button type="submit" disabled={loading} className="absolute right-4 top-1/2 -translate-y-1/2 p-2 rounded-xl text-slate-400 hover:text-blue-500 transition-colors">
                  {loading ? <div className="w-5 h-5 border-2 border-blue-500 border-t-transparent rounded-full animate-spin" /> : <Plus size={24} />}
                </button>
              </form>

              {translationResult && (
                <div className="bg-white rounded-3xl p-6 shadow-xl shadow-slate-200/50 border border-slate-100 space-y-4 animate-in zoom-in-95 duration-300">
                  <div className="flex justify-between items-start">
                    <div className="space-y-1 flex-1">
                      <h3 className="text-xl font-semibold text-slate-800">{translationResult.translation}</h3>
                      <p className="text-slate-400 text-sm font-mono tracking-wider">{translationResult.phonetic}</p>
                    </div>
                    <button onClick={() => speak(inputText)} className="p-3 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors">
                      <Volume2 size={20} />
                    </button>
                  </div>

                  <div className="space-y-3 pt-2 border-t border-slate-50">
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Definition</p>
                      <p className="text-sm text-slate-700 leading-relaxed font-medium">{translationResult.definitionEn}</p>
                    </div>
                    <div>
                      <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-1">Example</p>
                      <p className="text-slate-600 italic text-sm leading-relaxed bg-slate-50 p-3 rounded-xl border border-slate-100">
                        "{translationResult.exampleSentence}"
                      </p>
                    </div>
                  </div>

                  <button 
                    onClick={addToMemory}
                    className="w-full py-4 rounded-2xl bg-blue-500 text-white font-semibold hover:bg-blue-600 active:scale-[0.98] transition-all flex items-center justify-center gap-2 shadow-lg shadow-blue-500/25"
                  >
                    <Brain size={18} />
                    Learn this word
                  </button>
                </div>
              )}
            </section>

            <section className="space-y-4">
               <div className="flex items-center justify-between">
                 <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">Progress</h2>
                 <span className="text-[10px] text-blue-600 font-bold px-2 py-1 bg-blue-100/50 rounded-full">
                    {dueWords.length} due now
                 </span>
               </div>
               <div className="grid grid-cols-2 gap-4">
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">Vocabulary</p>
                    <p className="text-3xl font-light text-slate-800">{words.length}</p>
                  </div>
                  <div className="bg-white p-5 rounded-3xl border border-slate-100 shadow-sm">
                    <p className="text-[10px] font-bold uppercase tracking-wider text-slate-400 mb-1">Mastered</p>
                    <p className="text-3xl font-light text-green-500">{words.filter(w => w.stage === 11).length}</p>
                  </div>
               </div>
            </section>
          </div>
        )}

        {activeView === View.REVIEW && <ReviewMode key={dueWords.length > 0 ? 'active' : 'idle'} words={dueWords} onReview={updateWordStage} onSpeak={speak} />}

        {activeView === View.LIST && (
          <div className="space-y-4 animate-in fade-in duration-500">
            <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400 mb-6">Library</h2>
            {words.length === 0 ? (
               <div className="text-center py-20 text-slate-300 font-light italic">Your library is empty</div>
            ) : (
              <div className="space-y-3">
                {words.map(w => {
                  const timeInfo = formatNextReview(w.nextReviewDate);
                  const isExpanded = expandedSchedule === w.id;
                  return (
                    <div key={w.id} className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm transition-all">
                      <div className="p-5 flex items-center justify-between group">
                        <div className="space-y-1">
                          <h4 className="font-medium text-slate-800">{w.original}</h4>
                          <div className="flex items-center gap-2">
                            <span className="text-xs text-slate-400">{w.translation}</span>
                            <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                            <div className="flex items-center gap-1.5">
                              <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-1.5 py-0.5 rounded uppercase">LV {w.stage}</span>
                              <span className={`text-[10px] font-medium flex items-center gap-0.5 ${timeInfo.color}`}>
                                <Clock size={10} />
                                {timeInfo.text}
                              </span>
                            </div>
                          </div>
                        </div>
                        <div className="flex items-center gap-1">
                          <button 
                            onClick={() => setExpandedSchedule(isExpanded ? null : w.id)}
                            className={`p-2 rounded-full transition-colors ${isExpanded ? 'bg-slate-100 text-slate-600' : 'text-slate-300 hover:text-blue-500 hover:bg-blue-50'}`}
                          >
                            <CalendarDays size={18} />
                          </button>
                          <button onClick={() => deleteWord(w.id)} className="p-2 text-slate-200 hover:text-red-500 transition-all">
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </div>

                      {isExpanded && (
                        <div className="px-5 pb-5 pt-2 bg-slate-50/50 border-t border-slate-50 animate-in slide-in-from-top-2">
                          <div className="space-y-3">
                            <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mb-3">Ebbinghaus Retention Plan</p>
                            <div className="relative pl-4 space-y-4 before:absolute before:left-1 before:top-1 before:bottom-1 before:w-px before:bg-slate-200">
                              {REVIEW_INTERVALS.slice(1).map((interval, idx) => {
                                const stageNum = idx + 1;
                                const isDone = stageNum < w.stage;
                                const isCurrent = stageNum === w.stage;

                                let displayDate: Date;
                                if (isDone) {
                                  displayDate = new Date(w.createdAt); 
                                } else {
                                  displayDate = new Date(w.lastReviewDate + (isCurrent ? 0 : interval));
                                }

                                return (
                                  <div key={idx} className="relative flex items-center justify-between text-[11px]">
                                    <div className={`absolute -left-[15px] w-1.5 h-1.5 rounded-full z-10 ${isDone ? 'bg-green-500' : (isCurrent ? 'bg-blue-500 ring-4 ring-blue-100' : 'bg-slate-300')}`}></div>
                                    <span className={`${isDone ? 'text-slate-400 line-through' : (isCurrent ? 'text-blue-600 font-bold' : 'text-slate-500')}`}>
                                      Step {stageNum} ({getIntervalLabel(stageNum)})
                                    </span>
                                    <span className="text-slate-400 font-mono">
                                      {isCurrent ? 'Est: ' : ''}
                                      {isCurrent ? formatNextReview(w.nextReviewDate).text : displayDate.toLocaleDateString()}
                                    </span>
                                  </div>
                                );
                              })}
                            </div>
                          </div>
                        </div>
                      )}
                    </div>
                  );
                })}
              </div>
            )}
          </div>
        )}

        {activeView === View.STATS && (
           <div className="space-y-6 animate-in fade-in duration-500">
              <h2 className="text-xs font-bold uppercase tracking-[0.2em] text-slate-400">Memory Analytics</h2>
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
                <div className="flex flex-wrap gap-2 justify-center">
                  {Array.from({ length: 112 }).map((_, i) => (
                    <div 
                      key={i} 
                      className={`w-3 h-3 rounded-[2px] ${i % 12 === 0 ? 'bg-blue-400' : (i % 8 === 0 ? 'bg-blue-200' : 'bg-slate-100')}`} 
                    />
                  ))}
                </div>
                <div className="mt-8 flex justify-between items-end">
                   <div>
                     <p className="text-2xl font-light text-slate-800">84%</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Retention Rate</p>
                   </div>
                   <div className="text-right">
                     <p className="text-2xl font-light text-slate-800">12.4</p>
                     <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Words / Day</p>
                   </div>
                </div>
              </div>
           </div>
        )}
      </main>

      <nav className="fixed bottom-8 left-1/2 -translate-x-1/2 bg-white/90 backdrop-blur-2xl border border-white shadow-[0_20px_50px_rgba(0,0,0,0.1)] rounded-[2.5rem] p-2 flex items-center gap-1 z-50">
        <NavButton active={activeView === View.HOME} onClick={() => setActiveView(View.HOME)} icon={<Search size={22} />} label="Discover" />
        <NavButton 
          active={activeView === View.REVIEW} 
          onClick={() => setActiveView(View.REVIEW)} 
          icon={<Brain size={22} />} 
          label="Review" 
          badge={dueWords.length > 0 ? dueWords.length : undefined}
        />
        <NavButton active={activeView === View.LIST} onClick={() => setActiveView(View.LIST)} icon={<List size={22} />} label="Library" />
        <NavButton active={activeView === View.STATS} onClick={() => setActiveView(View.STATS)} icon={<BarChart3 size={22} />} label="Stats" />
      </nav>
    </div>
  );
};

const NavButton: React.FC<{ active: boolean; onClick: () => void; icon: React.ReactNode; label: string; badge?: number }> = ({ active, onClick, icon, label, badge }) => (
  <button 
    onClick={onClick}
    className={`relative px-5 py-3 rounded-[2rem] flex flex-col items-center gap-1 transition-all duration-300 ${active ? 'bg-blue-500 text-white shadow-lg shadow-blue-500/40 scale-105' : 'text-slate-400 hover:bg-slate-50'}`}
  >
    {icon}
    <span className="text-[9px] font-bold tracking-widest uppercase">{label}</span>
    {badge !== undefined && !active && (
      <span className="absolute top-1.5 right-3 w-4 h-4 bg-red-500 text-white text-[9px] font-bold flex items-center justify-center rounded-full animate-pulse border-2 border-white">
        {badge}
      </span>
    )}
  </button>
);

const ReviewMode: React.FC<{ words: Word[]; onReview: (id: string, rem: boolean) => void; onSpeak: (t: string) => void }> = ({ words, onReview, onSpeak }) => {
  // Directly initialize session queue to prevent the flickering "Completed" screen
  const [sessionQueue, setSessionQueue] = useState<string[]>(() => words.map(w => w.id));
  const [flipped, setFlipped] = useState(false);
  const [sessionCompletedCount, setSessionCompletedCount] = useState(0);

  const currentId = sessionQueue[0];
  const currentWord = words.find(w => w.id === currentId);

  // When words list empty or all finished
  if (!currentWord || sessionQueue.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center py-24 space-y-6 text-center animate-in zoom-in-95 duration-700">
        <div className="w-24 h-24 bg-blue-50 rounded-full flex items-center justify-center text-blue-500 shadow-inner">
          <Check size={48} className="animate-bounce" />
        </div>
        <div className="space-y-2">
          <h2 className="text-3xl font-light text-slate-800">Session Done</h2>
          <p className="text-slate-400 max-w-[200px] mx-auto text-sm">
            {sessionCompletedCount > 0 
              ? `You reviewed ${sessionCompletedCount} words today. Keep it up!` 
              : "No words due for review right now."}
          </p>
        </div>
      </div>
    );
  }

  const handleAction = (remembered: boolean) => {
    if (remembered) {
      // MASTERED for now: Advance global stage and remove from this session
      onReview(currentWord.id, true);
      setSessionQueue(prev => prev.slice(1));
      setSessionCompletedCount(prev => prev + 1);
    } else {
      // FORGOTTEN: Reset global stage to 1 and loop it back to the end of the current session
      onReview(currentWord.id, false);
      setSessionQueue(prev => {
        const remaining = prev.slice(1);
        return [...remaining, currentId]; 
      });
    }
    setFlipped(false);
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
      <div className="flex justify-between items-center px-2">
        <div className="flex items-center gap-2">
          <span className="w-2 h-2 rounded-full bg-blue-500"></span>
          <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.2em]">LEVEL {currentWord.stage} / 11</span>
        </div>
        <div className="flex flex-col items-end">
          <span className="text-[10px] font-bold text-blue-500 bg-blue-50 px-2 py-0.5 rounded-full tracking-wider">{sessionQueue.length} LEFT</span>
        </div>
      </div>

      <div onClick={() => setFlipped(!flipped)} className="relative h-[28rem] w-full perspective-1000 cursor-pointer active:scale-[0.99] transition-transform duration-200">
        <div className={`relative w-full h-full transition-transform duration-700 transform-style-3d ${flipped ? 'rotate-y-180' : ''}`}>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-center p-12 backface-hidden">
            <h3 className="text-4xl font-light text-slate-800 text-center leading-tight tracking-tight">{currentWord.original}</h3>
            <p className="mt-12 text-blue-400 text-[10px] font-bold uppercase tracking-[0.3em] flex items-center gap-2">Tap to flip</p>
          </div>
          <div className="absolute inset-0 bg-white rounded-[3rem] border border-slate-100 shadow-[0_30px_60px_-15px_rgba(0,0,0,0.1)] flex flex-col items-center justify-start p-8 backface-hidden rotate-y-180 text-center overflow-y-auto">
            <div className="w-full space-y-5">
              <div className="space-y-1">
                <h3 className="text-2xl font-bold text-slate-800 leading-tight">{currentWord.translation}</h3>
                <p className="text-slate-400 font-mono text-xs tracking-wider uppercase">{currentWord.phonetic}</p>
              </div>
              <div className="h-px w-16 bg-slate-100 mx-auto"></div>
              {currentWord.definitionEn && (
                <div className="text-left">
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">English Definition</p>
                  <p className="text-sm text-slate-700 leading-snug font-medium italic">{currentWord.definitionEn}</p>
                </div>
              )}
              <div className="text-left bg-slate-50/80 p-4 rounded-2xl border border-slate-100">
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-[0.2em] mb-2">Example</p>
                <p className="text-slate-600 italic text-sm leading-relaxed">"{currentWord.exampleSentence}"</p>
              </div>
              <div className="flex justify-center pt-2">
                <button onClick={(e) => { e.stopPropagation(); onSpeak(currentWord.original); }} className="p-4 bg-blue-50 rounded-full text-blue-500 hover:bg-blue-100 transition-colors shadow-sm">
                  <Volume2 size={24} />
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>

      {flipped && (
        <div className="flex gap-4 animate-in slide-in-from-bottom-8 duration-500 ease-out">
          <button onClick={() => handleAction(false)} className="flex-1 py-6 rounded-[2rem] bg-white border border-red-100 text-red-500 font-bold uppercase tracking-widest text-[10px] hover:bg-red-50 transition-colors shadow-sm flex items-center justify-center gap-2 group">
            <Undo2 size={16} className="group-active:-rotate-45 transition-transform" />
            Forgot (Loop)
          </button>
          <button onClick={() => handleAction(true)} className="flex-1 py-6 rounded-[2rem] bg-green-500 text-white font-bold uppercase tracking-widest text-[10px] hover:bg-green-600 transition-all shadow-xl shadow-green-500/30 flex items-center justify-center gap-2 group">
            <Check size={16} className="group-active:scale-125 transition-transform" />
            Got it (Master)
          </button>
        </div>
      )}
    </div>
  );
};

export default App;

